INSERT INTO `savsoft_notification` VALUES (174, 'DSSV được công nhận tham dự Lễ tri ân các nhà sáng lập & Ra mắt HĐT STU (Ngày 06/09/2024)', '<p>Mọi vấn đề thắc mắc Sinh viên vui lòng liên hệ qua fanpage của Phòng CTSV để được hỗ trợ và giải đáp thắc mắc trước 17h00 ngày 14/09/2024</p>\r\n\r\n<p>Sau thời gian trên Phòng sẽ không giải quyết khiếu nại và sẽ cập nhật vào hệ thống theo đúng đợt thông báo tổng hợp CTXH của Nhà trường.</p>\r\n\r\n<p><a href=\"/images/files/06-09-2024.pdf\">Danh sách Sinh viên tại đây:</a> </p>\r\n', 4290, '2024-09-07 08:35:34', '2024-09-07 08:35:34', '2024-09-07 08:35:34', NULL, 1);
INSERT INTO `savsoft_notification` VALUES (175, 'DSSV cộng ngày CTXH tham gia Tuần SHCD-SV giữa khóa, đầu khóa năm học 2024-2025', '<p>Mọi vấn đề thắc mắc Sinh viên vui lòng liên hệ qua fanpage của Phòng CTSV để được hỗ trợ và giải đáp thắc mắc trước 17h00 ngày 21/09/2024</p>\r\n\r\n<p>Sau thời gian trên Phòng sẽ không giải quyết khiếu nại và sẽ cập nhật vào hệ thống theo đúng đợt thông báo tổng hợp CTXH của Nhà trường.</p>\r\n\r\n<p><a href=\"/images/files/Set%20up.pdf\">DSSV hỗ trợ set-up Khám sức khỏe (Sáng ngày 30/8/2024):</a></p>\r\n\r\n<p><a href=\"/images/files/D%E1%BB%8Dn%20d%E1%BA%B9p.pdf\">DSSV hỗ trợ dọn dẹp sau Khám sức khỏe (Chiều ngày 07/9/2024):</a></p>\r\n\r\n<p><a href=\"/images/files/C%C3%B4ng%20t%C3%A1c%20Tr%E1%BB%B1c%20l%E1%BB%9Bp.pdf\">DSSV hỗ trợ trực lớp:</a></p>\r\n\r\n<p><a href=\"/images/files/C%C3%B4ng%20t%C3%A1c%20KSK.pdf\">DSSV hỗ trợ Khám sức khỏe:</a></p>\r\n\r\n<p></p>\r\n', 4290, '2024-09-14 15:14:38', '2024-09-23 09:52:46', '0000-00-00 00:00:00', NULL, 1);
INSERT INTO `savsoft_notification` VALUES (176, 'Tài liệu tham khảo Tuần SHCD - SV đầu khoá 2024-2025', '<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">1. Chuyên đề <strong>\"Quy chế công tác sinh viên\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Quy-che-CTSV.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">2. Chuyên đề <strong>\"Quy chế đào tạo các bậc học tại STU\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Quy-che-dao-tao.pdf\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">3. Chuyên đề <strong>\"Kỹ năng khai thác thông tin phục vụ học tập\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Khai-thac-thong-tin.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">4. Chuyên đề <strong>\"Đoàn thanh niên - Hội sinh viên\" </strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Doan-Hoi.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây </span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">5. Chuyên đề <strong>\"Tân sinh viên - Hành trình xây tương lai\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Tan-sinh-vien-hanh-trinh-xay%20-tuong-lai.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">6. Chuyên đề<strong> \"Thông tin Bảo hiểm y tế trong sinh viên\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/bao-hiem-y-te.ppt\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">7. Chuyên đề <strong>\"Giới thiệu trung tâm anh ngữ Horizon Tesol\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/Gi%E1%BB%9Bi%20thi%E1%BB%87u%20ch%C6%B0%C6%A1ng%20tr%C3%ACnh%20Ti%E1%BA%BFng%20Anh.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">8. Chuyên đề <strong>\"Thông tin thư viện STU\"</strong></span></span></p>\r\n\r\n<p><a href=\"/images/files/huong%20dan%20su%20dung%20thu%20vien%20tuan%20dau%20khoa%202024.pptx\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Sinh viên xem tài liệu tại đây</span></span></a></p>\r\n\r\n<p></p>\r\n', 4278, '2024-09-15 18:34:21', '2024-09-19 17:06:43', '0000-00-00 00:00:00', NULL, 1);
INSERT INTO `savsoft_notification` VALUES (177, 'DSSV công nhận ngày CTXH tham gia hỗ trợ trực an ninh tại trường (Từ ngày 04/9 - 14/9/2024)', '<p>Mọi vấn đề thắc mắc Sinh viên vui lòng liên hệ qua fanpage của Phòng CTSV để được hỗ trợ và giải đáp thắc mắc trước 17h00 ngày 23/09/2024.</p>\r\n\r\n<p>Sau thời gian trên Phòng sẽ không giải quyết khiếu nại và sẽ cập nhật vào hệ thống theo đúng đợt thông báo tổng hợp CTXH của Nhà trường.</p>\r\n\r\n<p><a href=\"/images/files/09-9-24.pdf\">Danh sách sinh viên tại đây:</a></p>\r\n', 4290, '2024-09-16 17:00:00', '2024-09-16 17:00:00', '2024-09-16 16:58:27', NULL, 1);
INSERT INTO `savsoft_notification` VALUES (178, 'DSSV chính thức được công nhận CTXH (trực an ninh & hỗ trợ Tuần SHCD-SV giữa khóa, cuối khóa)', '<p>Danh sách sinh viên chính thức được công nhận ngày CTXH bao gồm các chương trình:</p>\r\n\r\n<p>1. Hỗ trợ trực an ninh tại trường (từ ngày 04/9-14/9/2024):</p>\r\n\r\n<p>---- <a href=\"/images/files/Ch%C3%ADnh%20th%E1%BB%A9c%20tr%E1%BB%B1c%20an%20ninh.pdf\">Danh sách tại đây</a> ----</p>\r\n\r\n<p>2. Hỗ trợ các công tác trong Tuần sinh hoạt công - sinh viên giữa khóa, cuối khóa:</p>\r\n\r\n<p>---- <a href=\"/images/files/Set-up%20KSK.pdf\">Danh sách hỗ trợ set-up Khám sức khỏe (Sáng ngày 30/8/2024)</a> ----</p>\r\n\r\n<p>---- <a href=\"/images/files/D%E1%BB%8Dn%20d%E1%BA%B9p%20KSK.pdf\">Danh sách hỗ trợ dọn dẹp sau Khám sức khỏe (Chiều ngày 07/9/2024)</a> ----</p>\r\n\r\n<p>---- <a href=\"/images/files/Ch%C3%ADnh%20th%E1%BB%A9c%20tr%E1%BB%B1c%20l%E1%BB%9Bp.pdf\">Danh sách hỗ trợ trực lớp</a> ----</p>\r\n\r\n<p>---- <a href=\"/images/files/Ch%C3%ADnh%20th%E1%BB%A9c%20KSK.pdf\">Danh sách hỗ trợ Khám sức khỏe</a> ----</p>\r\n\r\n<p>Sau thời gian này Phòng không giải quyết khiếu nại và danh sách sẽ được cập nhật đúng đợt thông báo tổng hợp CTXH của Nhà trường. Riêng đối với sinh viên khóa cũ sẽ được cập nhật vào hồ sơ CTXH..</p>\r\n\r\n<p></p>\r\n', 4290, '2024-09-23 15:15:56', '2024-09-23 15:15:56', '2024-09-23 15:03:40', NULL, 1);
INSERT INTO `savsoft_notification` VALUES (179, 'DSSV dự kiến cộng ngày CTXH tham gia Tuần SHCD-SV đầu khóa năm học 2024-2025', '<p>Mọi vấn đề thắc mắc Sinh viên vui lòng liên hệ qua fanpage của Phòng CTSV để được hỗ trợ và giải đáp thắc mắc trước 17h00 ngày 30/09/2024</p>\r\n\r\n<p>Sau thời gian trên Phòng sẽ không giải quyết khiếu nại và sẽ cập nhật vào hệ thống theo đúng đợt thông báo tổng hợp CTXH của Nhà trường.</p>\r\n\r\n<p><a href=\"/images/files/%C4%90%E1%BB%81n%20H%C3%B9ng(1).pdf\">Danh sách hỗ trợ tham quan đền Hùng:</a></p>\r\n\r\n<p><a href=\"/images/files/Tr%E1%BB%B1c%20l%E1%BB%9Bp%20%C4%91%E1%BA%A7u%20kh%C3%B3a.pdf\">Danh sách hỗ trợ trực lớp:</a></p>\r\n', 4290, '2024-09-23 15:42:06', '2024-09-23 15:42:06', '2024-09-23 15:39:32', NULL, 1);
