INSERT INTO `savsoft_qbank` VALUES (87, 'Nhiều lựa chọn Một câu trả lời', 'Thái độ quan trọng hơn trình độ vì nó thể hiện sự tổng tu dưỡng và năng lực hấp thu giáo dục của cá nhân đó?', '', 10, 1, 590, 492, 90, 8);
INSERT INTO `savsoft_qbank` VALUES (88, 'Nhiều lựa chọn Một câu trả lời', 'Câu nói sau đây là của vị tổng thống nào?\r\n“Một yếu tố vô cùng đơn giản nhưng quan trọng nhất trong công thức thành công là xây dựng quan hệ tốt với mọi người”.', '', 6, 1, 1243, 609, 624, 10);
INSERT INTO `savsoft_qbank` VALUES (89, 'Nhiều lựa chọn Một câu trả lời', 'Andrew Carnegie, ông vua thép của Mỹ đã từng nói. “Tri thức của các chuyên gia chỉ chiếm …% trong thành công của họ, …% còn lại phụ thuộc vào các mối quan hệ xã hội”.', '', 6, 1, 1227, 783, 432, 12);
INSERT INTO `savsoft_qbank` VALUES (90, 'Nhiều lựa chọn Một câu trả lời', 'Theo tạp chí Wall Street Journal (2004), …% những người tìm việc thành công đều cho rằng networking chính là yếu tố giúp họ có được công việc mong muốn', '', 6, 1, 1309, 812, 484, 13);
INSERT INTO `savsoft_qbank` VALUES (91, 'Nhiều lựa chọn Một câu trả lời', 'Khi gặp người lạ ở một sự kiện xây dựng mạng lưới quan hệ như cuộc hội thảo, bữa tiệc gây quỹ từ thiện hay hoạt động giao lưu giữa các công ty, bạn nên nói chuyện về:', '', 6, 1, 1218, 829, 379, 10);
INSERT INTO `savsoft_qbank` VALUES (92, 'Nhiều lựa chọn Một câu trả lời', 'Nếu bạn cảm thấy khó khăn khi bắt chuyện với người khác trong sự kiện, bạn nên:', '', 6, 1, 1259, 584, 666, 9);
INSERT INTO `savsoft_qbank` VALUES (93, 'Nhiều lựa chọn Một câu trả lời', 'Lương, thu nhập, chưa hẳn phản ánh sự giàu có cá nhân nhưng nó phản ánh năng suất lao động của cá nhân đó?', '', 10, 1, 551, 376, 167, 8);
INSERT INTO `savsoft_qbank` VALUES (94, 'Nhiều lựa chọn Một câu trả lời', 'Khởi nghiệp ngay sau khi ra trường có phải là một lựa chọn đúng đắn cho một cá nhân khi theo đuổi sự đam mê?', '', 10, 1, 538, 100, 435, 3);
INSERT INTO `savsoft_qbank` VALUES (95, 'Nhiều lựa chọn Một câu trả lời', 'Việc chịu đựng những bất công, không hợp lý trong công sở, nơi làm việc, là một điều hết sức bình thường mà cá nhân nào cũng phải trải qua?', '', 10, 1, 517, 293, 216, 8);
INSERT INTO `savsoft_qbank` VALUES (96, 'Nhiều lựa chọn Một câu trả lời', 'Suy nghĩ ngắn hạn sẽ hoạch định cá nhân là “live” (cuộc sống), suy nghĩ dài hạn, bền vững sẽ hoạch định cá nhân là “life” (cuộc đời)?', '', 10, 1, 546, 484, 51, 11);
INSERT INTO `savsoft_qbank` VALUES (97, 'Nhiều lựa chọn Một câu trả lời', 'Bạn cho rằng người giao tiếp giỏi là người:', '', 6, 1, 1273, 266, 995, 12);
INSERT INTO `savsoft_qbank` VALUES (98, 'Nhiều lựa chọn Một câu trả lời', 'Người ta nhịn bạn, không có nghĩa người ta sợ bạn - mà họ muốn giữ lại tư cách cho riêng mình. Người ta nói lời xin lỗi bạn, không hẳn người ta sai với bạn - mà họ trân trọng những gì từng đẹp trong quá khứ. Người ta mềm mỏng với bạn, không phải người ta tiếc nuối bạn - mà bởi vì họ đã không bao giờ ngoảnh mặt lại để chứng kiến một cuộc chia ly?', '', 10, 1, 546, 427, 107, 12);
INSERT INTO `savsoft_qbank` VALUES (99, 'Nhiều lựa chọn Một câu trả lời', 'Người không có sự chuẩn bị là đã chuẩn bị cho sự thất bại?', '', 10, 1, 546, 455, 82, 9);
