INSERT INTO `savsoft_qbank` VALUES (101, 'Nhiều lựa chọn Một câu trả lời', 'Cách tốt nhất để thể hiện sự tôn trọng với những gì người khác nói là:', '', 6, 1, 1294, 1191, 92, 11);
INSERT INTO `savsoft_qbank` VALUES (102, 'Nhiều lựa chọn Một câu trả lời', 'Làm trái ngành học, trái sở trường; khiến năng lực của bạn sẽ kém cỏi đi?', '', 10, 1, 567, 181, 382, 4);
INSERT INTO `savsoft_qbank` VALUES (103, 'Nhiều lựa chọn Một câu trả lời', 'Nếu nhà tuyển dụng chỉ nhìn tấm bằng của bạn thay vì kiểm tra năng lực của bạn để nhận hoặc từ chối bạn vào làm việc; bạn có nên cộng tác hay không?', '', 10, 1, 541, 288, 246, 7);
