INSERT INTO `savsoft_qbank` VALUES (146, 'Nhiều lựa chọn Một câu trả lời', 'Những lưu ý khi sử dụng facebook là gì?\r\n1.Tuyệt đối không được nói tục, chửi bậy hoặc văng bậy, kể cả chửi bậy bằng những thứ viết tắt. Phải sử dụng ngôn ngữ trong sáng, thuần Việt.\r\n2.Chỉ like Status khi đã đọc kỹ nội dung của nó. Nếu like những status có nội dung xấu, chủ nhân Facebook sẽ bị quy trách nhiệm. Bởi vậy, cần phải biết đấu tranh, bảy tỏ quan điểm trước status có nội dung xấu hoặc không lành mạnh.\r\n3.Tuyệt đối, không được để bạn bè hiểu lầm khi đọc status. Bởi vậy viết status phải rõ ràng.\r\n4.Facebook cũng là nơi thể hiện được sự văn hóa của mỗi cá nhân, bởi vậy nên cân nhắc kỹ trước khi lên like vào một comment nào đó, hoặc viết status thể hiện tâm trạng của bản thân.\r\n5.Facebook không phải là nhật ký, bởi thế mọi riêng tư không nên đưa lên Facebook.', '', 10, 1, 575, 245, 320, 10);
INSERT INTO `savsoft_qbank` VALUES (147, 'Nhiều lựa chọn Một câu trả lời', 'Hệ thống thông tin quan trọng về an ninh quốc gia trừ thông tin quân sự và thông tin cơ yếu thuộc Ban Cơ yếu Chính phủ do ai thẩm định?', '', 6, 1, 1245, 248, 987, 10);
INSERT INTO `savsoft_qbank` VALUES (148, 'Nhiều lựa chọn Một câu trả lời', 'Các hành vi bị cấm trên mạng theo luật an ninh mạng năm 2018 là gì?', '', 10, 1, 536, 520, 15, 1);
INSERT INTO `savsoft_qbank` VALUES (149, 'Nhiều lựa chọn Một câu trả lời', 'Không gian mạng quốc gia là gì?', '', 6, 1, 1201, 465, 728, 8);
INSERT INTO `savsoft_qbank` VALUES (151, 'Nhiều lựa chọn Một câu trả lời', 'Trang thông tin điện tử, cổng thông tin điện tử hoặc chuyên trang trên mạng xã hội của cơ quan, tổ chức, cá nhân không được cung cấp, đăng tải, truyền đưa thông tin có nội dung nào dưới đây?', '', 6, 1, 1275, 92, 1172, 11);
INSERT INTO `savsoft_qbank` VALUES (152, 'Nhiều lựa chọn Một câu trả lời', '<p>Luật An ninh mạng có hiệu lực kể từ ngày tháng năm nào?</p>\r\n', '', 6, 1, 1222, 929, 280, 13);
INSERT INTO `savsoft_qbank` VALUES (153, 'Nhiều lựa chọn Một câu trả lời', 'Những lưu ý khi sử dụng facebook là gì?\r\n1. Tuyệt đối không được nói tục, chửi bậy hoặc văng bậy, kể cả chửi bậy bằng những thứ viết tắt. Phải sử dụng ngôn ngữ trong sáng, thuần Việt.\r\n2. Chỉ like Status khi đã đọc kỹ nội dung của nó. Nếu like những status có nội dung xấu, chủ nhân Facebook sẽ bị quy trách nhiệm. Bởi vậy, cần phải biết đấu tranh, bảy tỏ quan điểm trước status có nội dung xấu hoặc không lành mạnh.\r\n3 Tuyệt đối, không được để bạn bè hiểu lầm khi đọc status. Bởi vậy viết status phải rõ ràng.\r\n4. Facebook cũng là nơi thể hiện được sự văn hóa của mỗi cá nhân, bởi vậy nên cân nhắc kỹ trước khi lên like vào một comment nào đó, hoặc viết status thể hiện tâm trạng của bản thân.\r\n5.  Facebook không phải là nhật ký, bởi thế mọi riêng tư không nên đưa lên Facebook.', '', 6, 1, 1235, 446, 779, 10);
INSERT INTO `savsoft_qbank` VALUES (154, 'Nhiều lựa chọn Một câu trả lời', 'Các hành vi bị cấm trên mạng theo luật an ninh mạng năm 2018 là gì?', '', 6, 1, 1240, 1199, 31, 10);
INSERT INTO `savsoft_qbank` VALUES (156, 'Nhiều lựa chọn Một câu trả lời', '<p>&ldquo;T&iacute;n dụng đen&rdquo; l&agrave; g&igrave;?</p>\r\n', '', 1, 1, 1677, 1454, 218, 5);
INSERT INTO `savsoft_qbank` VALUES (157, 'Nhiều lựa chọn Một câu trả lời', '<p>Mục ti&ecirc;u chung của Đề &aacute;n &ldquo; Ph&ograve;ng ngừa tội phạm v&agrave; ph&ograve;ng, chống vi phạm ph&aacute;p luật trong học sinh sinh vi&ecirc;n đến năm 2020&rdquo; l&agrave;:</p>\r\n', '', 1, 1, 1687, 1566, 114, 7);
INSERT INTO `savsoft_qbank` VALUES (158, 'Nhiều lựa chọn Một câu trả lời', '<p>Vai tr&ograve; của Sinh vi&ecirc;n trong việc Ph&ograve;ng ngừa tội phạm v&agrave; ph&ograve;ng, chống vi phạm ph&aacute;p luật l&agrave; g&igrave;?</p>\r\n', '', 1, 1, 1649, 1596, 46, 7);
INSERT INTO `savsoft_qbank` VALUES (159, 'Nhiều lựa chọn Một câu trả lời', '<p>Chỉ thị 12/CT-TTg ng&agrave;y 25/4/2019 về tăng cường ph&ograve;ng ngừa, đấu tranh với tội phạm v&agrave; vi phạm ph&aacute;p luật li&ecirc;n quan đến &ldquo;t&iacute;n dụng đen&rdquo; Thủ tướng Ch&iacute;nh phủ y&ecirc;u cầu đối với Bộ GD&amp;ĐT l&agrave; g&igrave;?</p>\r\n', '', 1, 1, 1645, 1453, 183, 9);
INSERT INTO `savsoft_qbank` VALUES (160, 'Nhiều lựa chọn Một câu trả lời', '<p>Qui định về Văn h&oacute;a STU được ban h&agrave;nh v&agrave;o thời gian n&agrave;o?</p>\r\n', '', 1, 1, 1697, 1133, 555, 9);
INSERT INTO `savsoft_qbank` VALUES (161, 'Nhiều lựa chọn Một câu trả lời', '<p>C&oacute; bao nhi&ecirc;u điều quy định về văn h&oacute;a trong Qui định về &quot;Văn h&oacute;a STU&quot;?</p>\r\n', '', 1, 1, 1699, 963, 717, 19);
INSERT INTO `savsoft_qbank` VALUES (162, 'Nhiều lựa chọn Một câu trả lời', '<p>Đối tượng &aacute;p dụng trong quy định về Văn h&oacute;a&nbsp;STU bao gồm:</p>\r\n', '', 1, 1, 1658, 1472, 176, 10);
INSERT INTO `savsoft_qbank` VALUES (163, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy định: &quot; Ăn mặc nghi&ecirc;m chỉnh, lịch sự, gọn g&agrave;ng, sạch sẽ v&agrave; khi v&agrave;o Trường, mặc đồng phục (theo quy định, nếu c&oacute;), đeo ph&ugrave; hiệu hoặc bảng t&ecirc;n theo quy định;&quot; d&agrave;nh cho đối tượng n&agrave;o v&agrave; thuộc quy định về văn h&oacute;a n&agrave;o trong quy định về &quot;Văn h&oacute;a STU&quot;?</p>\r\n', '', 1, 1, 1694, 1049, 631, 14);
INSERT INTO `savsoft_qbank` VALUES (164, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tư tưởng Hồ Chí Minh được chính thức đưa vào văn kiện từ Đại hội lần thứ mấy của Đảng?</span></span></p>\r\n', '', 7, 1, 2868, 1528, 1300, 40);
INSERT INTO `savsoft_qbank` VALUES (165, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Vì sao Nguyễn Ái Quốc cho rằng cách mạng tư sản chỉ là cuộc cách mạng nửa vời, không triệt để?</span></span></p>\r\n', '', 7, 1, 2830, 1292, 1492, 46);
INSERT INTO `savsoft_qbank` VALUES (166, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Vì sao Đảng lấy Chủ nghĩa Mác, Lê nin, tư tưởng Hồ Chí Minh là nền tảng tư tưởng, kim chỉ nam cho mọi hành động của Đảng ta?</span></span></p>\r\n', '', 7, 1, 2889, 2604, 247, 38);
INSERT INTO `savsoft_qbank` VALUES (167, 'Nhiều lựa chọn Một câu trả lời', '<p>Nhà Thanh có ao bèo 1.000m2, ngày hôm sau số lượng bèo sẽ nở gấp đôi ngày hôm trước, đến ngày thứ 18 thì bèo đã nở được nửa ao. Vậy đến ngày thứ bao nhiêu thì bèo sẽ nở đầy ao?</p>\r\n', '', 11, 1, 13175, 5337, 5805, 2033);
INSERT INTO `savsoft_qbank` VALUES (168, 'Nhiều lựa chọn Một câu trả lời', '<p>9 – 6 - 1; 27 – 1 - 2; 6 - 3 - ?</p>\r\n', '', 11, 1, 13083, 4396, 6530, 2157);
INSERT INTO `savsoft_qbank` VALUES (169, 'Nhiều lựa chọn Một câu trả lời', '<p>Số tiếp theo của dãy 19, 28, 37, 46, ... là số nào? </p>\r\n', '', 11, 1, 12924, 8929, 2032, 1963);
INSERT INTO `savsoft_qbank` VALUES (170, 'Nhiều lựa chọn Một câu trả lời', '<p>Hãy tính dãy số sau đây: 1 + 2 + 3 + ..... + 99 = ...........</p>\r\n', '', 11, 1, 13035, 5888, 5050, 2097);
INSERT INTO `savsoft_qbank` VALUES (171, 'Nhiều lựa chọn Một câu trả lời', '<p>Minh 4 tuổi, tuổi anh Minh gấp 3 lần tuổi Minh. Khi anh Minh bao nhiêu tuổi thì tuổi anh Minh chỉ còn gấp đôi tuổi Minh? </p>\r\n', '', 11, 1, 13035, 6053, 4799, 2183);
INSERT INTO `savsoft_qbank` VALUES (172, 'Nhiều lựa chọn Một câu trả lời', '<p>John có 10 đôi tất. Nếu anh ta mất 7 chiếc tất riêng lẻ thì số đôi nhiều nhất mà anh ta còn lại là bao nhiêu? </p>\r\n', '', 11, 1, 13053, 5732, 5339, 1982);
INSERT INTO `savsoft_qbank` VALUES (173, 'Nhiều lựa chọn Một câu trả lời', '<p>Một đội bóng rổ chơi được 2/3 trận đấu và đã thắng 17 bàn, thua 3 bàn. Trong suốt trận đấu còn lại đội bóng có thể thua nhiều nhất bao nhiêu mà vẫn thắng ít nhất 3/4 toàn trận đấu?</p>\r\n', '', 11, 1, 13110, 3629, 7313, 2168);
INSERT INTO `savsoft_qbank` VALUES (177, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></span></span></p>\r\n', '', 12, 1, 6, 6, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (178, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></span></span></p>\r\n', '', 12, 1, 4, 0, 4, 0);
INSERT INTO `savsoft_qbank` VALUES (179, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 12, 1, 15, 5, 10, 0);
INSERT INTO `savsoft_qbank` VALUES (180, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></span></p>\r\n', '', 12, 1, 15, 12, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (181, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Danh hiệu thi đua khen thưởng đối với cá nhân dành cho Sinh viên STU đạt thành tích trong học tập và rèn luyện?</span></p>\r\n', '', 12, 1, 16, 14, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (182, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Xác nhận của đơn vị nào không được nhà trường công nhận khi sinh viên tham gia chương trình công tác xã hội?</span></span></p>\r\n', '', 12, 1, 8, 4, 4, 0);
INSERT INTO `savsoft_qbank` VALUES (183, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></p>\r\n', '', 12, 1, 5, 3, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (184, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 12, 1, 15, 7, 8, 0);
INSERT INTO `savsoft_qbank` VALUES (185, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Theo quy định quy đổi ngày Công tác xã hội (CTXH), Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></p>\r\n', '', 12, 1, 16, 6, 10, 0);
INSERT INTO `savsoft_qbank` VALUES (186, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></p>\r\n', '', 12, 1, 9, 9, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (187, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 12, 1, 7, 4, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (188, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Thời gian khiếu nại về kết quả đánh giá điểm rèn luyện đối với Sinh viên hệ Đại học là bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></p>\r\n', '', 12, 1, 10, 3, 5, 2);
INSERT INTO `savsoft_qbank` VALUES (189, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Đánh giá kết quả rèn luyện của sinh viên dựa vào nội dung nào?</span></p>\r\n', '', 12, 1, 8, 5, 1, 2);
INSERT INTO `savsoft_qbank` VALUES (190, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Quy trình đánh giá kết quả rèn luyện của sinh viên STU như thế nào?</span></span></span></p>\r\n', '', 12, 1, 13, 10, 1, 2);
INSERT INTO `savsoft_qbank` VALUES (191, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sinh viên không tham gia đánh giá xếp loại thể lực hoặc tham gia nhưng không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></p>\r\n', '', 12, 1, 7, 4, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (192, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Theo quy định về việc đánh giá, xếp loại thể lực cho Sinh viên (SV) STU, mỗi SV được đánh giá bao nhiêu nội dung?</span></p>\r\n', '', 12, 1, 9, 6, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (193, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sinh viên không tham gia khám sức khỏe định kỳ hàng năm do nhà trường tổ chức sẽ bị xử lý như thế nào?</span></p>\r\n', '', 12, 1, 4, 3, 1, 0);
INSERT INTO `savsoft_qbank` VALUES (194, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></span></span></p>\r\n', '', 12, 1, 6, 6, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (195, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 12, 1, 4, 3, 1, 0);
INSERT INTO `savsoft_qbank` VALUES (196, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 12, 1, 9, 7, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (197, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></p>\r\n', '', 12, 1, 12, 4, 8, 0);
INSERT INTO `savsoft_qbank` VALUES (198, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Theo bạn dấu hiệu khác biệt trong phương pháp học đại học so với học phổ thông là gì?</span></span></p>\r\n', '', 12, 1, 15, 9, 6, 0);
INSERT INTO `savsoft_qbank` VALUES (199, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Khi cần tìm hiểu về một vấn đề bạn sẽ tìm thông tin ở đâu?</span></span></span></span></p>\r\n', '', 12, 1, 6, 6, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (200, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Nơi nào cung cấp các khóa học miễn phí trên internet?</span></span></p>\r\n', '', 12, 1, 16, 11, 5, 0);
INSERT INTO `savsoft_qbank` VALUES (201, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Nơi nào cung cấp các khóa học miễn phí trên internet?</span></span></p>\r\n', '', 12, 1, 9, 6, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (202, 'Nhiều lựa chọn Một câu trả lời', '<p>Muốn học những kỹ năng thì bạn tìm ở đâu?</p>\r\n', '', 12, 1, 7, 4, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (203, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên thiếu chuyên cần sẽ bị cấm thi khi nào?</span></span></p>\r\n', '', 12, 1, 17, 7, 8, 2);
INSERT INTO `savsoft_qbank` VALUES (204, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sinh viên đại học có thời gian tối đa bao nhiêu để hoàn thành chương trình đào tạo?</span></p>\r\n', '', 12, 1, 13, 11, 0, 2);
INSERT INTO `savsoft_qbank` VALUES (205, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Trong chương trình đào tạo khóa 2019, một giờ tín chỉ được quy định như thế nào?</span></p>\r\n', '', 12, 1, 5, 2, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (206, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối thiểu sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 12, 1, 8, 2, 6, 0);
INSERT INTO `savsoft_qbank` VALUES (207, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Một năm học tại Trường Đại học Công nghệ Sài Gòn gồm bao nhiêu học kỳ?</span></span></p>\r\n', '', 12, 1, 7, 7, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (208, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Tại trường Đại học Công nghệ Sài Gòn, tổng số tín chỉ cho mỗi chương trình đào tạo bậc Đại học là bao nhiêu?</span></p>\r\n', '', 12, 1, 17, 4, 11, 2);
INSERT INTO `savsoft_qbank` VALUES (209, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Xếp loại Trung bình khá được đánh giá theo thang điểm 4 là bao nhiêu?</span></span></p>\r\n', '', 12, 1, 4, 1, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (210, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên tích lũy đủ học phần, tín chỉ quy định trong chương trình đào tạo sẽ được xét tốt nghiệp. Ngoài ra, sinh viên phải đạt chứng chỉ của môn học nào?</p>\r\n', '', 12, 1, 10, 9, 1, 0);
INSERT INTO `savsoft_qbank` VALUES (211, 'Nhiều lựa chọn Một câu trả lời', '<p>Nhà trường phân công người cố vấn và hỗ trợ sinh viên phát huy tối đa khả năng học tập, lựa chọn môn học phù hợp, theo dõi thành tích học tập cho một sinh viên, nhóm sinh viên hay một lớp, được gọi là gì?</p>\r\n', '', 12, 1, 16, 14, 0, 2);
INSERT INTO `savsoft_qbank` VALUES (212, 'Nhiều lựa chọn Một câu trả lời', '<p>Vào cuối học kỳ, nhà trường tổng hợp kết quả học tập và xử lý học vụ những sinh viên có kết quả không đạt yêu cầu dưới các hình thức nào?</p>\r\n', '', 12, 1, 18, 16, 0, 2);
INSERT INTO `savsoft_qbank` VALUES (213, 'Nhiều lựa chọn Một câu trả lời', '<p>Điểm tổng kết môn học được tính dựa trên điểm thành phần nào?</p>\r\n', '', 12, 1, 18, 18, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (214, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Trường Đại học Công nghệ Sài Gòn được thành lập vào thời gian nào?</span></p>\r\n', '', 12, 1, 4, 4, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (215, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Trường hiện tại có bao nhiêu khoa đào tạo?</span></span></span></span></p>\r\n', '', 12, 1, 7, 3, 2, 2);
INSERT INTO `savsoft_qbank` VALUES (216, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Slogan của STU là gì?</span></span></span></p>\r\n', '', 12, 1, 9, 2, 7, 0);
INSERT INTO `savsoft_qbank` VALUES (217, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sứ mệnh của STU là gì?</span></p>\r\n', '', 12, 1, 17, 14, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (218, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Để làm các thủ tục về học vụ, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n', '', 12, 1, 7, 5, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (219, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Để liên hệ các hoạt động về nghiên cứu khoa học, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n', '', 12, 1, 4, 1, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (220, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Để liên hệ hỗ trợ các giấy xác nhận cho sinh viên như hoãn nghĩa vụ quân sự, vay vốn… sinh viên cần liên hệ  phòng ban nào?</span></span></span></span></p>\r\n', '', 12, 1, 10, 8, 0, 2);
INSERT INTO `savsoft_qbank` VALUES (221, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Để liên hệ hỗ trợ các vấn đề về Bảo hiểm y tế, sinh viên cần liên hệ phòng ban nào?</span></p>\r\n', '', 12, 1, 17, 2, 13, 2);
INSERT INTO `savsoft_qbank` VALUES (222, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Để làm các hồ sơ về giảm học phí, học bổng ... sinh viên cần liên hệ phòng ban nào?</span></span></span></p>\r\n', '', 12, 1, 12, 6, 6, 0);
INSERT INTO `savsoft_qbank` VALUES (223, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Tại STU, đơn vị chủ yếu tổ chức, xét duyệt các hoạt động CTXH là đơn vị nào?</span></p>\r\n', '', 12, 1, 12, 2, 10, 0);
INSERT INTO `savsoft_qbank` VALUES (224, 'Nhiều lựa chọn Một câu trả lời', '<p>Môn học chứa đựng nội dung kiến thức chính yếu của mỗi chương trình mà bắt buộc sinh viên phải tích lũy gọi là gì?</p>\r\n', '', 12, 1, 10, 7, 3, 0);
INSERT INTO `savsoft_qbank` VALUES (225, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Theo kiến thức đã học với giảng viên, thích nghi là gì?</span></span></span></span></p>\r\n', '', 13, 1, 26, 24, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (226, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Người thích nghi tốt có đặc điểm gì?</span></span></span></span></p>\r\n', '', 13, 1, 26, 3, 23, 0);
INSERT INTO `savsoft_qbank` VALUES (227, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Thích nghi tốt mang đến lợi ích gì?</span></span></span></span></p>\r\n', '', 13, 1, 26, 24, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (228, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Để thích nghi tốt, sinh viên cần lưu ý điều gì?</span></span></span></span></p>\r\n', '', 13, 1, 26, 24, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (229, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Gặp khó khăn trong quá trình thích nghi, sinh viên nên nhìn nhận đó như thế nào?</span></span></span></span></p>\r\n', '', 13, 1, 26, 15, 11, 0);
INSERT INTO `savsoft_qbank` VALUES (230, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\">Tại sao phải kiên nhẫn trong quá trình thích nghi?</span></span></span></p>\r\n', '', 13, 1, 26, 15, 11, 0);
INSERT INTO `savsoft_qbank` VALUES (231, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Thích nghi là quá trình sẽ xảy ra khi nào?</span></span></span></span></p>\r\n', '', 13, 1, 26, 14, 12, 0);
INSERT INTO `savsoft_qbank` VALUES (232, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, có bao nhiêu mức xử lý đối với sinh viên khi vi phạm kỷ luật?</p>\r\n', '', 12, 1, 13, 9, 4, 0);
INSERT INTO `savsoft_qbank` VALUES (233, 'Nhiều lựa chọn Một câu trả lời', '<p>Có bao nhiêu danh hiệu khen thưởng đối với cá nhân sinh viên?</p>\r\n', '', 12, 1, 16, 6, 10, 0);
INSERT INTO `savsoft_qbank` VALUES (234, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong quy định về an ninh trật tại STU, SV khi vào trường phải chấp hành nội quy:</p>\r\n', '', 12, 1, 12, 10, 0, 2);
INSERT INTO `savsoft_qbank` VALUES (235, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong quy định về Văn hóa STU, Văn hóa STU được áp dụng cho các đối tượng nào?</p>\r\n', '', 12, 1, 5, 3, 2, 0);
INSERT INTO `savsoft_qbank` VALUES (236, 'Nhiều lựa chọn Một câu trả lời', '<p>Có bao nhiêu giá trị văn hóa được quy định trong \"Văn hóa STU\"?</p>\r\n', '', 12, 1, 9, 3, 6, 0);
INSERT INTO `savsoft_qbank` VALUES (237, 'Nhiều lựa chọn Một câu trả lời', '<p>Đối tượng áp dụng thực hiện qui định về việc thực hiện công tác xã hội tại STU?</p>\r\n', '', 12, 1, 8, 2, 6, 0);
INSERT INTO `savsoft_qbank` VALUES (238, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy trình tổng hợp ngày công tác xã hội (CTXH) của sinh viên như thế nào?</p>\r\n', '', 12, 1, 14, 2, 10, 2);
INSERT INTO `savsoft_qbank` VALUES (239, 'Nhiều lựa chọn Một câu trả lời', '<p>Có bao nhiêu mức phân loại kết quả đánh giá rèn luyện cho sinh viên?</p>\r\n', '', 12, 1, 18, 4, 14, 0);
INSERT INTO `savsoft_qbank` VALUES (240, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy chế đánh giá kết quả rèn luyện của sinh viên ban hành theo quết định số 231/QĐ-DSG-CTSV ngày 01/08/2016 áp dụng cho đối tượng nào?</p>\r\n', '', 12, 1, 16, 7, 8, 1);
INSERT INTO `savsoft_qbank` VALUES (241, 'Nhiều lựa chọn Một câu trả lời', '<p>Mức kỷ luật sinh viên vi phạm lần 1 đối với hành vi thi, kiểm tra thay, hoặc nhờ thi, kiểm tra thay; làm thay, nhờ làm hoặc sao chép tiểu luận, đồ án, khóa luận tốt nghiệp  theo quy chế công tác sinh viên là gì?</p>\r\n', '', 12, 1, 12, 2, 8, 2);
INSERT INTO `savsoft_qbank` VALUES (244, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Theo quy định của Bộ Luật lao động, người lao động phải đủ bao nhiêu tuổi?</span></span></p>\r\n', '', 14, 1, 531, 278, 250, 3);
INSERT INTO `savsoft_qbank` VALUES (245, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo quy định của Bộ Luật lao động, những nội dung nào sau đây là quyền của người lao động?</p>\r\n', '', 14, 1, 546, 414, 131, 1);
INSERT INTO `savsoft_qbank` VALUES (246, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật lao động quy định người lao động có nghĩa vụ gì?</p>\r\n', '', 14, 1, 483, 466, 12, 5);
INSERT INTO `savsoft_qbank` VALUES (247, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo quy định của Bộ Luật lao động, nguyên tắc giao kết hợp đồng lao động như thế nào?</p>\r\n', '', 14, 1, 523, 444, 75, 4);
INSERT INTO `savsoft_qbank` VALUES (248, 'Nhiều lựa chọn Một câu trả lời', '<p>Căn cứ quy định của Bộ Luật lao động, nội dung nào sau đây không phải quyền của người sử dụng lao động?</p>\r\n', '', 14, 1, 554, 289, 261, 4);
INSERT INTO `savsoft_qbank` VALUES (249, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật lao động quy định nghiêm cấm những hành vi nào của người sử dụng lao động khi thực hiện giao kết hợp đồng lao động?</p>\r\n', '', 14, 1, 547, 510, 34, 3);
INSERT INTO `savsoft_qbank` VALUES (250, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật Lao động quy định hợp đồng lao động phải được giao kết theo những loại nào?</p>\r\n', '', 14, 1, 537, 407, 125, 5);
INSERT INTO `savsoft_qbank` VALUES (251, 'Nhiều lựa chọn Một câu trả lời', '<p>Thời gian thử việc theo quy định của Bộ Luật Lao động như thế nào?</p>\r\n', '', 14, 1, 508, 365, 136, 7);
INSERT INTO `savsoft_qbank` VALUES (252, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật Lao động quy định nghĩa vụ vủa người lao động khi đơn phương chấm dứt hợp đồng lao động trái pháp luật như thế nào?</p>\r\n', '', 14, 1, 517, 447, 66, 4);
INSERT INTO `savsoft_qbank` VALUES (253, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật Lao động quy định tiền lương làm thêm giờ của người lao động được tính như thế nào?</p>\r\n', '', 14, 1, 544, 21, 517, 6);
INSERT INTO `savsoft_qbank` VALUES (254, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo quy định của bộ Luật Lao động, người lao động được nghỉ việc riêng không hưởng lương và phải thông báo với người sử dụng lao động trong trường hợp sau đây?</p>\r\n', '', 14, 1, 521, 239, 277, 5);
INSERT INTO `savsoft_qbank` VALUES (255, 'Nhiều lựa chọn Một câu trả lời', '<p>Bộ Luật Lao động quy định thời gian nghỉ thai sản của lao động nữ như thế nào?</p>\r\n', '', 14, 1, 540, 366, 172, 2);
INSERT INTO `savsoft_qbank` VALUES (256, 'Nhiều lựa chọn Một câu trả lời', '<p>Người sử dụng lao động không được đơn phương chấm dứt hợp đồng lao động với lao động nữ vì các lý do nào sau đây?</p>\r\n', '', 14, 1, 537, 477, 57, 3);
INSERT INTO `savsoft_qbank` VALUES (257, 'Nhiều lựa chọn Một câu trả lời', '<p>Một số trường hợp người sử dụng lao động không được xử lý kỷ luật người lao động theo quy định của Bộ Luật Lao động?</p>\r\n', '', 14, 1, 543, 522, 16, 5);
INSERT INTO `savsoft_qbank` VALUES (258, 'Nhiều lựa chọn Một câu trả lời', '<p>Các hành vi bị nghiêm cấm đối với người sử dụng lao động theo quy định của Bộ Luật Lao động?</p>\r\n', '', 14, 1, 557, 517, 36, 4);
INSERT INTO `savsoft_qbank` VALUES (259, 'Nhiều lựa chọn Một câu trả lời', '<p>Chuyên đề học tập và làm theo tư tưởng, đạo đức, phong cách Hồ Chí Minh năm 2020 là gì?</p>\r\n', '', 15, 1, 1782, 898, 875, 9);
INSERT INTO `savsoft_qbank` VALUES (260, 'Nhiều lựa chọn Một câu trả lời', '<p>Đoạn viết dưới đây ghi lại các luận điểm của hồ Chí Minh về đại đoàn kết. Trong số những luận điểm này, luận điểm nào được Hồ Chí Minh viết trong Di chúc?</p>\r\n', '', 15, 1, 1748, 1089, 642, 17);
INSERT INTO `savsoft_qbank` VALUES (261, 'Nhiều lựa chọn Một câu trả lời', '<p>Ham muốn tột bậc của Hồ Chí Minh là gì/</p>\r\n', '', 15, 1, 1743, 1658, 73, 12);
INSERT INTO `savsoft_qbank` VALUES (262, 'Nhiều lựa chọn Một câu trả lời', '<p>Lực lượng thực hiện đại đoàn kết dân tộc bao gồm những ai?</p>\r\n', '', 15, 1, 1745, 564, 1168, 13);
INSERT INTO `savsoft_qbank` VALUES (263, 'Nhiều lựa chọn Một câu trả lời', '<p>\"Quan sơn muôn dặm một nhà<br />\r\nVì trong bốn biển đều là anh em.\"</p>\r\n\r\n<p>Hai câu thơ trên Bác viết trong hoàn cảnh nào?</p>\r\n', '', 15, 1, 1757, 1096, 648, 13);
INSERT INTO `savsoft_qbank` VALUES (264, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo tư tưởng Hồ Chí Minh công tác xây dựng Đảng bao gồm các nội dung gì?</p>\r\n', '', 15, 1, 1796, 464, 1318, 14);
INSERT INTO `savsoft_qbank` VALUES (265, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo Hồ Chí Minh tinh thần quốc tế trong sáng được hiểu là:</p>\r\n', '', 15, 1, 1789, 81, 1692, 16);
INSERT INTO `savsoft_qbank` VALUES (266, 'Nhiều lựa chọn Một câu trả lời', '<p>Câu \"Nhân dân ta thường nói: Đảng viên đi trước, làng nước theo sau\"  được trích từ tác phẩm nào của Hồ Chí Minh?</p>\r\n', '', 15, 1, 1766, 1361, 392, 13);
INSERT INTO `savsoft_qbank` VALUES (267, 'Nhiều lựa chọn Một câu trả lời', '<p>Các câu dưới đây ghi lại các luận điểm của Hồ Chí Minh về đại đoàn kết. Trong số những luận điểm này, luận điểm nào được Hồ Chí Minh viết trong Đoàn kết tiến lên giành thắng lợi mới?</p>\r\n', '', 15, 1, 1793, 441, 1341, 11);
INSERT INTO `savsoft_qbank` VALUES (268, 'Nhiều lựa chọn Một câu trả lời', '<p>Tác phẩm \"Hồ Chí Minh - Tinh hoa và khí phách của dân tộc\" do ai sáng tác?</p>\r\n', '', 15, 1, 1762, 1513, 238, 11);
INSERT INTO `savsoft_qbank` VALUES (269, 'Nhiều lựa chọn Một câu trả lời', '<p>Nói về vai trò của đạo đức, Hồ Chí Minh viết: \"Trước mặt quần chúng, không phải ta cứ viết lên trán chữ \"cộng sản\" mà ta được họ yêu mến. Quần chúng chỉ quý mến những người có tư cách, đạo đức.\"</p>\r\n\r\n<p>Đoạn văn trên được Người viết ra trong tác phẩm nào sau đây?</p>\r\n', '', 15, 1, 1830, 1224, 590, 16);
INSERT INTO `savsoft_qbank` VALUES (270, 'Nhiều lựa chọn Một câu trả lời', '<p>Bác nói: \"Không sợ kẻ thù nào dù cho chúng hung tợn đến mấy, không sợ nhiệm vụ nào dù nặng nề nguy hiểm đến mấy, nhưng Đảng Lao động Việt Nam sẵn sàng vui vẻ làm trâu ngựa, làm tôi tớ trung thành của nhân dân\" trong hoàn cảnh nào?</p>\r\n', '', 15, 1, 1781, 1135, 633, 13);
INSERT INTO `savsoft_qbank` VALUES (271, 'Nhiều lựa chọn Một câu trả lời', '<p>Đâu là nguyên tắc sinh hoạt Đảng?</p>\r\n', '', 15, 1, 1789, 1623, 156, 10);
INSERT INTO `savsoft_qbank` VALUES (272, 'Nhiều lựa chọn Một câu trả lời', '<p>Để phát huy vai trò lãnh đạo của Đảng trong hệ thống chính trị, Chủ tịch Hồ CHí Minh chú trọng xây dựng phong cách lãnh đạo nào sau đây?</p>\r\n', '', 15, 1, 1786, 807, 962, 17);
INSERT INTO `savsoft_qbank` VALUES (273, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong di chúc của Chủ tịch Hồ Chí Minh (Bản được công bố năm 1969), điều mong muốn cuối cùng của Chủ tịch Hồ Chí Minh là gì?</p>\r\n', '', 15, 1, 1786, 1379, 393, 14);
INSERT INTO `savsoft_qbank` VALUES (274, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo quan điểm của Chủ tịch Hồ Chí Minh, \"Dân vận\" là gì?</p>\r\n', '', 15, 1, 1775, 1453, 306, 16);
INSERT INTO `savsoft_qbank` VALUES (275, 'Nhiều lựa chọn Một câu trả lời', '<p>\"Dân tộc ta, nhân dân ta, non sông đất nước ta đã sinh ra Hồ Chủ Tịch, người anh hùng dân tộc vĩ đại, và chính Người đã làm rạng rỡ dân tộc ta, nhân dân ta và non sông đất nước ta\".</p>\r\n\r\n<p>Câu trên được trích từ văn kiện nào sau đây/</p>\r\n', '', 15, 1, 1747, 1205, 531, 11);
INSERT INTO `savsoft_qbank` VALUES (276, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo Bác, kẻ thù hung ác của chủ nghĩa xã hội là gì?</p>\r\n', '', 15, 1, 1831, 1121, 695, 15);
INSERT INTO `savsoft_qbank` VALUES (277, 'Nhiều lựa chọn Một câu trả lời', '<p>\"Đoàn kết là một truyền thống cực kỳ quý báu của Đảng ta, của dân ta. Các đồng chí từ trung ương đến các chi bộ cần phải giữ gìn sự đoàn kết nhất trí của Đảng như giữ gìn con ngươi của mắt mình\". Hồ chí Minh nói câu đó ở văn kiện nào?</p>\r\n', '', 15, 1, 1792, 1302, 475, 15);
INSERT INTO `savsoft_qbank` VALUES (278, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong lời kết thúc buổi ra mắt của Đảng Lao động Việt Nam, Hồ CHí Minh nói: \"Mục đich của Đảng Lao động Việt Nam có thể gồm 8 chữ là: ĐOÀN KẾT TOÀN DÂN, PHỤNG SỰ TỔ QUỐC\". Buổi ra mắt đó là vào lúc nào?</p>\r\n', '', 15, 1, 1782, 1446, 324, 12);
INSERT INTO `savsoft_qbank` VALUES (279, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo anh Trần Đức Sự - Phó giám đốc trung tâm phát triển khoa học và công nghệ trẻ - Thành đoàn Tp.Hồ CHí Minh, việc thực hiện một đề tài nghiên cứu khoa học có bao nhiêu bước?</p>\r\n', '', 16, 1, 2417, 1531, 869, 17);
INSERT INTO `savsoft_qbank` VALUES (280, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, việc thực hiện đề tài nghiên cứu khoa học có bao nhiêu bước cơ bản?</p>\r\n', '', 16, 1, 2417, 581, 1818, 18);
INSERT INTO `savsoft_qbank` VALUES (281, 'Nhiều lựa chọn Một câu trả lời', '<p>Việc nghiên cứu khoa học trong sinh viên có những lợi ích gì?</p>\r\n', '', 16, 1, 2417, 2138, 265, 14);
INSERT INTO `savsoft_qbank` VALUES (282, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, sinh viên có thể liên hệ bộ phận nào để hướng dẫn thực hiện đề tài?</p>\r\n', '', 16, 1, 2417, 1229, 1175, 13);
INSERT INTO `savsoft_qbank` VALUES (283, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, sinh viên có thể xem thông tin, quy định về việc nghiên cứu khoa học tại đâu?</p>\r\n', '', 16, 1, 2417, 1832, 568, 17);
INSERT INTO `savsoft_qbank` VALUES (284, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, sinh viên nhận các biểu mẫu liên quan đến thực hiện đề tài nghiên cứu khoa học ở đâu?</p>\r\n', '', 16, 1, 2417, 563, 1839, 15);
INSERT INTO `savsoft_qbank` VALUES (285, 'Nhiều lựa chọn Một câu trả lời', '<p>Tại STU, Khoa chuyên môn đóng vai trò gì trong việc thực hiện đề tài nghiên cứu khoa học của sinh viên?</p>\r\n', '', 16, 1, 2417, 2266, 135, 16);
INSERT INTO `savsoft_qbank` VALUES (286, 'Nhiều lựa chọn Một câu trả lời', '<p>Xác nhận CTXH của đơn vị nào sau đây không được nhà trường công nhận?</p>\r\n', '', 18, 1, 2141, 757, 1376, 8);
INSERT INTO `savsoft_qbank` VALUES (287, 'Nhiều lựa chọn Một câu trả lời', '<p>Sai khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</p>\r\n', '', 18, 1, 2094, 1058, 1028, 8);
INSERT INTO `savsoft_qbank` VALUES (288, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy trình đánh giá kết quả rèn luyện của sinh viên STU như thế nào?</p>\r\n', '', 18, 1, 2164, 1716, 440, 8);
INSERT INTO `savsoft_qbank` VALUES (289, 'Nhiều lựa chọn Một câu trả lời', '<p>Hình thức xử lý sinh viên không tham gia khám sức khỏe định kỳ do nhà trường tổ chức là gì?</p>\r\n', '', 18, 1, 2119, 1514, 596, 9);
INSERT INTO `savsoft_qbank` VALUES (290, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy chế thực hiện ngày CTXH áp dụng cho đối tượng sinh viên nào của nhà trường?</p>\r\n', '', 1, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (291, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo Quy định về công tác y tế học đường của sinh viên STU và khám sức khỏe định kỳ hàng năm áp dụng cho sinh viên năm thứ mấy?</p>\r\n', '', 18, 1, 2108, 1982, 117, 9);
INSERT INTO `savsoft_qbank` VALUES (292, 'Nhiều lựa chọn Một câu trả lời', '<p>Đơn vị nào đánh giá điểm rèn luyện cuối cùng tại trường?</p>\r\n', '', 18, 1, 2155, 1238, 907, 10);
INSERT INTO `savsoft_qbank` VALUES (293, 'Nhiều lựa chọn Một câu trả lời', '<p>Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</p>\r\n', '', 18, 1, 2141, 1766, 367, 8);
INSERT INTO `savsoft_qbank` VALUES (294, 'Nhiều lựa chọn Một câu trả lời', '<p>Mục đích của Sinh viên khai báo Ngoại trú là gì?</p>\r\n', '', 18, 1, 2129, 1958, 162, 9);
INSERT INTO `savsoft_qbank` VALUES (295, 'Nhiều lựa chọn Một câu trả lời', '<p>Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</p>\r\n', '', 18, 1, 2110, 778, 1319, 13);
INSERT INTO `savsoft_qbank` VALUES (296, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo Quy định Sinh viên đánh giá thể lực đựa trên mấy nội dung kiểm tra?</p>\r\n', '', 18, 1, 2154, 2030, 116, 8);
INSERT INTO `savsoft_qbank` VALUES (297, 'Nhiều lựa chọn Một câu trả lời', '<p>Đối tượng Sinh viên nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</p>\r\n', '', 18, 1, 2122, 1878, 232, 12);
INSERT INTO `savsoft_qbank` VALUES (298, 'Nhiều lựa chọn Một câu trả lời', '<p>Có bao nhiêu đối tượng sinh viên được xét giảm học phí tại trường?</p>\r\n', '', 18, 1, 2105, 993, 1096, 16);
INSERT INTO `savsoft_qbank` VALUES (299, 'Nhiều lựa chọn Một câu trả lời', '<p>Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với sinh viên là từ bao nhiêu điểm?</p>\r\n', '', 18, 1, 2180, 1028, 1141, 11);
INSERT INTO `savsoft_qbank` VALUES (300, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong một năm học tại trường có bao nhiêu đợt xét giảm học phí?</p>\r\n', '', 18, 1, 2122, 1807, 299, 16);
INSERT INTO `savsoft_qbank` VALUES (301, 'Nhiều lựa chọn Một câu trả lời', '<p>Điểm trung bình ở học kỳ hoặc năm trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường từ bao nhiêu điểm?</p>\r\n', '', 18, 1, 2163, 999, 1153, 11);
INSERT INTO `savsoft_qbank` VALUES (302, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được quy đổi thành 01 ngày CTXH?</p>\r\n', '', 1, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (303, 'Nhiều lựa chọn Một câu trả lời', '<p>Khen thưởng trong thực hiện CTXH dành cho đối tượng nào?</p>\r\n', '', 18, 1, 2143, 1951, 182, 10);
INSERT INTO `savsoft_qbank` VALUES (304, 'Nhiều lựa chọn Một câu trả lời', '<p>Khen thưởng \"Học tập tốt - Rèn luyện tốt\" có bao nhiêu mức?</p>\r\n', '', 18, 1, 2112, 857, 1237, 18);
INSERT INTO `savsoft_qbank` VALUES (305, 'Nhiều lựa chọn Một câu trả lời', '<p>Khen thưởng loại giỏi trong \"Học tập tốt - Rèn luyện tốt\" bao gồm các tiêu chí nào?</p>\r\n', '', 18, 1, 2201, 1626, 563, 12);
INSERT INTO `savsoft_qbank` VALUES (306, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên thực hiện bao nhiêu tiêu chí đạt trong quy định đánh giá thể lực thì sẽ được công nhận đạt?</p>\r\n', '', 18, 1, 2114, 1884, 219, 11);
INSERT INTO `savsoft_qbank` VALUES (307, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên vi phạm vào việc \"Thi, kiểm tra thay, hoặc nhờ thi, kiểm tra thay; làm thay, nhờ làm hoặc sao chép tiểu luận, đồ án, khóa luận tốt nghiệp\" lần 1 sẽ bị xử lý theo quy chế công tác sinh viên như thế nào?</p>\r\n', '', 18, 1, 2075, 1263, 804, 8);
INSERT INTO `savsoft_qbank` VALUES (308, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên không hoàn thành ngày CTXH khi ra trường sẽ bị xử lý như thế nào?</p>\r\n', '', 1, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (309, 'Nhiều lựa chọn Một câu trả lời', '<p>Quy trình tổng hợp ngày CTXH của sinh viên như thế nào?</p>\r\n', '', 18, 1, 2100, 1760, 332, 8);
INSERT INTO `savsoft_qbank` VALUES (310, 'Nhiều lựa chọn Một câu trả lời', '<p>Dự luật mới được Nhà nước ban hành trong năm 2020 là gì?</p>\r\n', '', 18, 1, 2134, 1165, 958, 11);
INSERT INTO `savsoft_qbank` VALUES (311, 'Nhiều lựa chọn Một câu trả lời', '<p>Luật Thanh niên năm 2020 được thông qua vào ngày tháng năm nào?</p>\r\n', '', 18, 1, 2168, 1911, 246, 11);
INSERT INTO `savsoft_qbank` VALUES (312, 'Nhiều lựa chọn Một câu trả lời', '<p>Luật Thanh niên năm 2020 có hiệu lực từ ngày tháng năm nào?</p>\r\n', '', 18, 1, 2158, 1622, 522, 14);
INSERT INTO `savsoft_qbank` VALUES (313, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo Luật Thanh niên 2020, tổ chức nào là tổ chức xã hội rộng rãi của Thanh niên Việt Nam?</p>\r\n', '', 18, 1, 2158, 1085, 1060, 13);
INSERT INTO `savsoft_qbank` VALUES (314, 'Nhiều lựa chọn Một câu trả lời', '<p>Để cân bằng tâm lý trong mùa dịch Covid-19, sinh viên cần phải làm gì?</p>\r\n', '', 17, 1, 3558, 737, 2787, 34);
