INSERT INTO `savsoft_qbank` VALUES (360, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"color:null\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Theo bạn dấu hiệu khác biệt trong phương pháp học đại học so với học phổ thông là gì?</span></span></span></p>\r\n', '', 21, 1, 4146, 3534, 592, 20);
INSERT INTO `savsoft_qbank` VALUES (361, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Khi cần tìm hiểu về một vấn đề bạn sẽ tìm thông tin ở đâu?</span></span></span></span></p>\r\n', '', 21, 1, 4146, 4081, 47, 18);
INSERT INTO `savsoft_qbank` VALUES (362, 'Nhiều lựa chọn Một câu trả lời', '<div class=\"O0\" style=\"margin-bottom:0pt; margin-left:.56in; margin-top:5.28pt; text-align:left\"><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Muốn học những kỹ năng thì bạn tìm ở đâu?</span></span></div>\r\n', '', 21, 1, 4146, 2090, 2034, 22);
INSERT INTO `savsoft_qbank` VALUES (363, 'Nhiều lựa chọn Một câu trả lời', '<p>Điều gì quan trọng nhất trong việc học?</p>\r\n', '', 21, 1, 4146, 1976, 2150, 20);
INSERT INTO `savsoft_qbank` VALUES (364, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên đại học có thời gian tối đa để hoàn thành chương trình đào tạo (CTĐT) là bao lâu?</p>\r\n', '', 22, 1, 2313, 1645, 648, 20);
INSERT INTO `savsoft_qbank` VALUES (365, 'Nhiều lựa chọn Một câu trả lời', '<p>Một năm học tại Trường Đại học Công nghệ Sài Gòn gồm bao nhiêu học kỳ?</p>\r\n', '', 22, 1, 2228, 1637, 575, 16);
INSERT INTO `savsoft_qbank` VALUES (366, 'Nhiều lựa chọn Một câu trả lời', '<p>Môn học chứa đựng nội dung kiến thức chính yếu của mỗi chương trình mà sinh viên phải tích lũy gọi là gì?</p>\r\n', '', 22, 1, 2324, 1814, 495, 15);
INSERT INTO `savsoft_qbank` VALUES (367, 'Nhiều lựa chọn Một câu trả lời', '<p>Điểm tổng kết môn học được tính dựa trên điểm thành phần nào sau đây?</p>\r\n', '', 22, 1, 2340, 2271, 54, 15);
INSERT INTO `savsoft_qbank` VALUES (368, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên thiếu chuyên cần sẽ bị cấm thi khi nào?</p>\r\n', '', 22, 1, 2246, 1462, 773, 11);
INSERT INTO `savsoft_qbank` VALUES (369, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối thiểu sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</p>\r\n', '', 22, 1, 2233, 1069, 1148, 16);
INSERT INTO `savsoft_qbank` VALUES (370, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối đa sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</p>\r\n', '', 22, 1, 2205, 836, 1354, 15);
INSERT INTO `savsoft_qbank` VALUES (371, 'Nhiều lựa chọn Một câu trả lời', '<p>Vào cuối học kỳ, nhà trường tổng hợp kết quả học tập và xử lý học vụ những sinh viên có kết quả không đạt yêu cầu dưới hình thức nào?</p>\r\n', '', 22, 1, 2212, 1053, 1147, 12);
INSERT INTO `savsoft_qbank` VALUES (372, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên tích lũy đủ học phần, tín chỉ quy định trong CTĐT sẽ được xét tốt nghiệp. Ngoài ra, sinh viên phải đạt chứng chỉ của môn học nào sau đây?</p>\r\n', '', 22, 1, 2284, 1431, 838, 15);
INSERT INTO `savsoft_qbank` VALUES (373, 'Nhiều lựa chọn Một câu trả lời', '<p>Một trong những điều kiện xét tốt nghiệp, Điểm trung bình chung tích lũy của toàn khóa học đạt từ bao nhiêu?</p>\r\n', '', 22, 1, 2229, 530, 1691, 8);
INSERT INTO `savsoft_qbank` VALUES (374, 'Nhiều lựa chọn Một câu trả lời', '<p>Nhà trường phân công người cố vấn và hỗ trợ sinh viên phát huy tối đa khả năng học tập, lựa chọn môn học phù hợp, theo dõi thành tích học tập cho một sinh viên, nhóm sinh viên hay một lớp, gọi là gì?</p>\r\n', '', 22, 1, 2237, 2124, 95, 18);
INSERT INTO `savsoft_qbank` VALUES (375, 'Nhiều lựa chọn Một câu trả lời', '<p>Trong CTĐT khóa 2020, một giờ tín chỉ được quy định bằng những giờ nào?</p>\r\n', '', 22, 1, 2248, 892, 1342, 14);
INSERT INTO `savsoft_qbank` VALUES (376, 'Nhiều lựa chọn Một câu trả lời', '<p>Sinh viên không hoàn thành CTĐT và đã vượt quá thời gian tối đa được phép đào tạo tại Trường sẽ bị xử lý thế nào?</p>\r\n', '', 22, 1, 2259, 1395, 854, 10);
INSERT INTO `savsoft_qbank` VALUES (377, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Vì sao chúng ta phải quản trị bản thân?</span></span></p>\r\n', '', 33, 1, 581, 439, 137, 5);
INSERT INTO `savsoft_qbank` VALUES (378, 'Nhiều lựa chọn Một câu trả lời', '<p>Chúng ta quản trị bản thân bằng cách nào?</p>\r\n', '', 33, 1, 643, 139, 502, 2);
INSERT INTO `savsoft_qbank` VALUES (379, 'Nhiều lựa chọn Một câu trả lời', '<p>Chúng ta sẽ làm gì để quản trị bản thân? Hay ta phải xác định điều gì?</p>\r\n', '', 33, 1, 626, 580, 42, 4);
INSERT INTO `savsoft_qbank` VALUES (380, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo bạn, bộ kỹ năng nhận thức và quản trị bản thân bao gồm những gì?</p>\r\n', '', 33, 1, 614, 508, 100, 6);
INSERT INTO `savsoft_qbank` VALUES (381, 'Nhiều lựa chọn Một câu trả lời', '<p>Công thức để quản trị cảm xúc hiệu quả là gì?</p>\r\n', '', 33, 1, 603, 115, 485, 3);
INSERT INTO `savsoft_qbank` VALUES (382, 'Nhiều lựa chọn Một câu trả lời', '<p>Làm cách nào để bạn quản lý thời gian hiệu quả?</p>\r\n', '', 33, 1, 587, 178, 404, 5);
INSERT INTO `savsoft_qbank` VALUES (383, 'Nhiều lựa chọn Một câu trả lời', '<p>Làm cách nào để bạn có thể hiểu và phát huy thế mạnh của bản thân?</p>\r\n', '', 33, 1, 650, 614, 32, 4);
INSERT INTO `savsoft_qbank` VALUES (384, 'Nhiều lựa chọn Một câu trả lời', '<p>Bạn hiểu như thế nào về khả năng tự tạo động lực bản thân? </p>\r\n', '', 33, 1, 600, 555, 43, 2);
INSERT INTO `savsoft_qbank` VALUES (385, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo bạn, 4 yếu tố cần thiết để xây dựng khả năng tự tạo động lực là gì?</p>\r\n', '', 33, 1, 597, 581, 15, 1);
INSERT INTO `savsoft_qbank` VALUES (386, 'Nhiều lựa chọn Một câu trả lời', '<p>Bạn sẽ phát triển thói quen mới tích cực bằng cách nào?</p>\r\n', '', 33, 1, 609, 588, 19, 2);
INSERT INTO `savsoft_qbank` VALUES (387, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Bộ Luật Lao động năm 2019 có hiệu lực ngày tháng năm nào? gồm bao nhiêu chương, bao nhiều điều?</span></span></p>\r\n', '', 30, 1, 1818, 1189, 570, 59);
INSERT INTO `savsoft_qbank` VALUES (388, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Hình thức của hợp đồng lao động gồm?</span></span></p>\r\n', '', 30, 1, 1769, 1356, 374, 39);
INSERT INTO `savsoft_qbank` VALUES (389, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:16px\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Hợp đồng lao động bằng lời nói áp dụng trong trường hợp nào?</span></span></p>\r\n', '', 30, 1, 1772, 1496, 243, 33);
INSERT INTO `savsoft_qbank` VALUES (390, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Không áp dụng thử việc đối với người lao động giao kết hợp đồng lao động có thời hạn dưới bao nhiêu tháng?</span></span></p>\r\n', '', 30, 1, 1775, 1457, 285, 33);
INSERT INTO `savsoft_qbank` VALUES (391, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thời gian thử việc đối với công việc có chức danh nghề nghiệp cần trình độ chuyên môn, kỹ thuật từ cao đẳng trở lên là bao nhiêu ngày?</span></span></p>\r\n', '', 30, 1, 1760, 1196, 510, 54);
INSERT INTO `savsoft_qbank` VALUES (392, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thời gian thử việc đối với công việc có chức danh nghề nghiệp cần trình độ chuyên môn, kỹ thuật trung cấp, công nhân kỹ thuật, nhân viên nghiệp vụ là bao nhiêu ngày?</span></span></p>\r\n', '', 30, 1, 1747, 118, 1578, 51);
INSERT INTO `savsoft_qbank` VALUES (393, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tiền lương của người lao động trong thời gian thử việc do hai bên thỏa thuận nhưng ít nhất phải bằng bao nhiêu phần trăm mức lương của công việc đó?</span></span></p>\r\n', '', 30, 1, 1802, 1447, 301, 54);
INSERT INTO `savsoft_qbank` VALUES (394, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:13.0pt\">Trường hợp nào dưới đây không được tạm hoãn thực hiện hợp đồng lao động?</span></span></span></p>\r\n', '', 30, 1, 1784, 738, 995, 51);
INSERT INTO `savsoft_qbank` VALUES (395, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:13.0pt\">Người lao động là người Việt Nam được nghỉ làm việc, hưởng nguyên lương bao nhiêu ngày trong những ngày lễ tết của năm?</span></span></span></p>\r\n', '', 30, 1, 1805, 1148, 608, 49);
INSERT INTO `savsoft_qbank` VALUES (396, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Người lao động kết hôn thì được nghỉ hưởng nguyên lương mấy ngày?</span></span></p>\r\n', '', 30, 1, 1792, 1599, 141, 52);
INSERT INTO `savsoft_qbank` VALUES (397, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Lao động nữ được nghỉ thai sản trước và sau khi sinh con là bao nhiêu tháng?</span></span></p>\r\n', '', 30, 1, 1741, 1596, 95, 50);
INSERT INTO `savsoft_qbank` VALUES (398, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:13.0pt\"><span style=\"color:black\">Công dân đến sinh sống tại chỗ ở hợp pháp ngoài phạm vi đơn vị hành chính cấp xã nơi đã đăng ký thường trú để lao động, học tập hoặc vì mục đích khác từ </span></span><span style=\"font-size:13.0pt\"><span style=\"color:black\">bao nhiêu</span></span><span style=\"font-size:13.0pt\"><span style=\"color:black\"> ngày trở lên thì phải thực hiện đăng ký tạm tr</span></span><span style=\"font-size:13.0pt\"><span style=\"color:black\">ú?</span></span></span></span></p>\r\n', '', 32, 1, 2030, 1740, 233, 57);
INSERT INTO `savsoft_qbank` VALUES (399, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thời hạn tạm trú tối đa là </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">bao lâu</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"> và có </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">được</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"> gia hạn </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">không?</span></span></p>\r\n', '', 32, 1, 1978, 1566, 379, 33);
INSERT INTO `savsoft_qbank` VALUES (400, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Công </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><span style=\"color:black\">dân được đăng ký thường trú tại chỗ ở hợp pháp do thuê, mượn, ở nhờ khi đáp ứng các điều kiện</span></span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><span style=\"color:black\"> nào</span></span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><span style=\"color:black\"> sau đây</span></span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><span style=\"color:black\">?</span></span></span></p>\r\n', '', 32, 1, 1841, 1036, 745, 60);
INSERT INTO `savsoft_qbank` VALUES (401, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Kể từ ngày 01/7/2021, sổ hộ khẩu, sổ tạm trú đã được cấp vẫn được sử dụng và có giá trị như giấy tờ, tài liệu xác nhận về cư trú cho đến hết ngày </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">nào sau đây?</span></span></p>\r\n', '', 32, 1, 1977, 1673, 257, 47);
INSERT INTO `savsoft_qbank` VALUES (402, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thanh niên là người bao nhiêu tuổi?</span></span></p>\r\n', '', 31, 1, 1904, 603, 1271, 30);
INSERT INTO `savsoft_qbank` VALUES (403, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tháng Thanh niên là tháng mấy?</span></span></p>\r\n', '', 31, 1, 2038, 1898, 109, 31);
INSERT INTO `savsoft_qbank` VALUES (404, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đối thoại với Thanh niên được tổ chức bao nhiêu lần trong một năm?</span></span></p>\r\n', '', 31, 1, 1946, 1369, 531, 46);
INSERT INTO `savsoft_qbank` VALUES (405, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thanh niên hoàn thành nghĩa vụ quân sự, nghĩa vụ tham gia Công an nhân dân được hưởng chính sách</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"> gì?</span></span></p>\r\n', '', 31, 1, 1938, 1416, 468, 54);
INSERT INTO `savsoft_qbank` VALUES (407, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm?</span></span></span></span></p>\r\n', '', 29, 1, 2437, 1032, 1349, 56);
INSERT INTO `savsoft_qbank` VALUES (408, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 29, 1, 2476, 845, 1597, 34);
INSERT INTO `savsoft_qbank` VALUES (409, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></p>\r\n', '', 29, 1, 2453, 1019, 1375, 59);
INSERT INTO `savsoft_qbank` VALUES (410, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></span></span></p>\r\n', '', 29, 1, 2439, 2008, 384, 47);
INSERT INTO `savsoft_qbank` VALUES (411, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Để làm các hồ sơ về giảm học phí, học bổng, sinh viên cần liên hệ phòng ban nào?</span></span></p>\r\n', '', 29, 1, 2467, 1397, 1033, 37);
INSERT INTO `savsoft_qbank` VALUES (412, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tại trường STU, hiện nay có mấy loại học bổng dành cho Sinh viên? </span></span></p>\r\n', '', 29, 1, 2460, 1198, 1214, 48);
INSERT INTO `savsoft_qbank` VALUES (413, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Mức vay vốn đối với  sinh viên tại Ngân hàng chính sách xã hội địa phương là bao nhiêu/tháng?</span></span></p>\r\n', '', 29, 1, 2428, 1685, 683, 60);
INSERT INTO `savsoft_qbank` VALUES (414, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Theo Nghị định số 81/2021/NĐ-CP, đối tượng nào được miễn giảm 50% học phí tại địa phương?</span></span></p>\r\n', '', 29, 1, 2403, 1541, 812, 50);
INSERT INTO `savsoft_qbank` VALUES (415, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></span></span></p>\r\n', '', 29, 1, 2464, 809, 1602, 53);
