INSERT INTO `savsoft_qbank` VALUES (417, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></span></span></p>\r\n', '', 29, 1, 2425, 865, 1488, 72);
INSERT INTO `savsoft_qbank` VALUES (418, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></span></span></p>\r\n', '', 29, 1, 2464, 610, 1797, 57);
INSERT INTO `savsoft_qbank` VALUES (419, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></span></span></p>\r\n', '', 29, 1, 2444, 510, 1887, 47);
INSERT INTO `savsoft_qbank` VALUES (420, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></span></span></p>\r\n', '', 29, 1, 2422, 901, 1476, 45);
INSERT INTO `savsoft_qbank` VALUES (421, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Khen thưởng trong thực hiện CTXH dành cho đối tượng nào?</span></span></p>\r\n', '', 29, 1, 2437, 1950, 436, 51);
INSERT INTO `savsoft_qbank` VALUES (422, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Trong một năm học tại trường có bao nhiêu đợt xét giảm học phí?</span></span></span></span></p>\r\n', '', 29, 1, 2433, 1953, 428, 52);
INSERT INTO `savsoft_qbank` VALUES (423, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Theo Quy định về công tác y tế học đường của sinh viên STU và khám sức khỏe định kỳ hàng năm áp dụng cho sinh viên năm thứ mấy?</span></span></span></span></p>\r\n', '', 29, 1, 2422, 2235, 142, 45);
INSERT INTO `savsoft_qbank` VALUES (424, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></span></span></p>\r\n', '', 29, 1, 2436, 2160, 231, 45);
INSERT INTO `savsoft_qbank` VALUES (487, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đại hội XIII của Đảng diễn ra trong bối cảnh dịch bệnh nào đang diễn biến phức tạp?</span></span></p>\r\n', '', 28, 1, 1752, 1667, 66, 19);
INSERT INTO `savsoft_qbank` VALUES (488, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Chủ đề Đại hội XIII của Đảng là gì? </span></span></p>\r\n', '', 28, 1, 1765, 1394, 339, 32);
INSERT INTO `savsoft_qbank` VALUES (489, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Nguyên nhân quan trọng nhất của những thành tựu qua 5 năm thực hiện Nghị quyết Đại hội XII của Đảng là gì?</span></span></p>\r\n', '', 28, 1, 1651, 1544, 65, 42);
INSERT INTO `savsoft_qbank` VALUES (490, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đại hội XIII của Đảng đánh giá tổng quát 35 năm thực hiện công cuộc đổi mới, 30 năm thực hiện Cương lĩnh xây đựng dất nước trong thời kỳ quá độ lên chủ nghĩa xã hội như thế nào ? </span></span></p>\r\n', '', 28, 1, 1744, 1421, 291, 32);
INSERT INTO `savsoft_qbank` VALUES (491, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><a href=\"https://daihoidang.vn/trien-khai-nghi-quyet-dai-hoi-xiii-cua-dang-van-hoi-moi-cua-dat-nuoc/1776.vnp\" style=\"color:blue; text-decoration:underline\" title=\"Triển khai Nghị quyết Đại hội XIII của Đảng: Vận hội mới của đất nước\"><span style=\"font-size:13.0pt\">Đại hội XIII của Đảng</span></a></span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"> bầu ai giữ nhiệm vụ Tổng Bí thư ? </span></span></p>\r\n', '', 28, 1, 1726, 1627, 81, 18);
INSERT INTO `savsoft_qbank` VALUES (492, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đại hội XIII đã bầu được bao nhiêu Ủy viên Ban Chấp hành Trung ương Đảng? </span></span></p>\r\n', '', 28, 1, 1708, 1458, 228, 22);
INSERT INTO `savsoft_qbank` VALUES (493, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Ban Chấp hành Trung ương Đảng khóa XIII đã bầu được bao nhiêu đồng chí Ủy viên Bộ Chính </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">250trị Ban Chấp hành Trung ương khóa XIII?</span></span></p>\r\n', '', 28, 1, 1653, 1357, 274, 22);
INSERT INTO `savsoft_qbank` VALUES (494, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Mục tiêu cụ thể phát triển đất nước trong thời gian tới được Đại hội XIII xác định gồm những giai đoạn nào? </span></span></p>\r\n', '', 28, 1, 1725, 1445, 238, 42);
INSERT INTO `savsoft_qbank` VALUES (495, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Thành tố nào không nằm trong mục tiêu tổng quát phát triển đất nước được Đại hội XIII đề ra?</span></span></p>\r\n', '', 28, 1, 1740, 1287, 416, 37);
INSERT INTO `savsoft_qbank` VALUES (496, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021-2025,<strong> </strong>tốc độ tăng trưởng GDP bình quân cả nước đạt khoảng bao nhiêu phần trăm một năm?</span></span></p>\r\n', '', 28, 1, 1783, 1582, 180, 21);
INSERT INTO `savsoft_qbank` VALUES (497, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, GDP bình quân đầu người đạt tỷ lệ bao nhiêu?</span></span></p>\r\n', '', 28, 1, 1742, 1511, 198, 33);
INSERT INTO `savsoft_qbank` VALUES (498, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, tỷ lệ đô thị hóa đạt khoảng bao nhiêu phần trăm?</span></span></p>\r\n', '', 28, 1, 1752, 1442, 270, 40);
INSERT INTO `savsoft_qbank` VALUES (499, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, kinh tế số đạt tỷ lệ bao nhiêu phần trăm GDP?</span></span></p>\r\n', '', 28, 1, 1759, 1050, 681, 28);
INSERT INTO `savsoft_qbank` VALUES (500, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, tỷ lệ lao động qua đào tạo đạt bao nhiêu phần trăm? </span></span></p>\r\n', '', 28, 1, 1764, 1259, 472, 33);
INSERT INTO `savsoft_qbank` VALUES (501, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, tỷ lệ tham gia bảo hiểm y tế đạt bao nhiêu phần trăm dân số cả nước? </span></span></p>\r\n', '', 28, 1, 1732, 1454, 250, 28);
INSERT INTO `savsoft_qbank` VALUES (502, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, tỷ lệ sử dụng nước sạch, nước hợp vệ sinh của dân cư nông thôn là bao nhiêu phần trăm?</span></span></p>\r\n', '', 28, 1, 1682, 1245, 411, 26);
INSERT INTO `savsoft_qbank` VALUES (503, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 5 năm 2021 - 2025, tỷ lệ che phủ rừng ổn định của cả nước ở mức bao nhiêu phần trăm?<strong>  </strong></span></span></p>\r\n', '', 28, 1, 1722, 1400, 296, 26);
INSERT INTO `savsoft_qbank` VALUES (504, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Những đột phá chiến lược được Đại hội XIII được nêu trong Chiến lược phát triển kinh tế - xã hội 10 năm 2021 - 2030 là gì? </span></p>\r\n', '', 28, 1, 1705, 1560, 112, 33);
INSERT INTO `savsoft_qbank` VALUES (505, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Chọn đáp án đúng về nguyên nhân khách quan của những hạn chế, yếu kém trong thực hiện nhiệm vụ phát triển kinh tế - xã hội được trình bày trong văn kiện Đại hội đại biểu toàn quốc lần thứ XIII của Đảng? </span></span></p>\r\n', '', 28, 1, 1682, 1329, 307, 46);
INSERT INTO `savsoft_qbank` VALUES (506, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Chọn đáp án đúng nhất thể hiện những nội dung về nhiệm vụ, giải pháp chủ yếu về phát triển kinh tế - xã hội trong giai đoạn 2021 - 2025 được trình bày trong Báo cáo chính trị của Ban Chấp hành Trung ương Đảng khóa XIII?</span></span></p>\r\n', '', 28, 1, 1766, 1553, 168, 45);
INSERT INTO `savsoft_qbank` VALUES (507, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Chọn đáp án đúng nhất về phương hướng, nhiệm vụ phòng, chống tham nhũng, thực hành tiết kiệm, chống lãng phí giai đoạn 2021 - 2025?</span></span></p>\r\n', '', 28, 1, 1710, 1351, 303, 56);
INSERT INTO `savsoft_qbank` VALUES (508, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đại hội XIII đề ra bao nhiêu định hướng phát triển đất nước giai đoạn 2021 - 2030?</span></span></p>\r\n', '', 28, 1, 1751, 1083, 624, 44);
INSERT INTO `savsoft_qbank` VALUES (509, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Có bao nhiêu nhiệm vụ trọng tâm trong nhiệm kỳ Đại hội XIII của Đảng? </span></span></p>\r\n', '', 28, 1, 1691, 1349, 307, 35);
INSERT INTO `savsoft_qbank` VALUES (510, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 10 năm 2021 - 2030, tổng đầu tư xã hội bình quân đạt tỷ lệ bao nhiêu phần trăm GDP?</span></span></p>\r\n', '', 28, 1, 1732, 943, 752, 37);
INSERT INTO `savsoft_qbank` VALUES (511, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 10 năm 2021 - 2030, tốc độ tăng năng suất lao động xã hội bình quân cả nước đạt bao nhiêu phần trăm trên năm?</span></span></p>\r\n', '', 28, 1, 1747, 1389, 326, 32);
INSERT INTO `savsoft_qbank` VALUES (512, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 10 năm 2021 - 2030, chỉ số phát triển con người (HDI) duy trì ở tỷ lệ bao nhiêu?</span></span></p>\r\n', '', 28, 1, 1684, 1320, 333, 31);
INSERT INTO `savsoft_qbank` VALUES (513, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Phấn đấu trong 10 năm 2021 - 2030, tỷ trọng lao động nông nghiệp trong tổng lao động xã hội giảm xuống bao nhiêu phần trăm? </span></span></p>\r\n', '', 28, 1, 1712, 950, 718, 44);
INSERT INTO `savsoft_qbank` VALUES (514, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Đại hội XIII của Đảng đề ra bao nhiêu phương hướng, nhiệm vụ, giải pháp phát triển kinh tế - xã hội 10 năm 2021 - 2030? </span></span></p>\r\n', '', 28, 1, 1722, 690, 982, 50);
INSERT INTO `savsoft_qbank` VALUES (515, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Có mấy nhiệm vụ, giải pháp về công tác xây dựng Đảng trong nhiệm kỳ 2021 - 2026? </span></span></p>\r\n', '', 28, 1, 1734, 634, 1060, 40);
INSERT INTO `savsoft_qbank` VALUES (516, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tính đến năm 2020, tỷ lệ các khu công nghiệp, khu chế xuất đang hoạt động trên cả nước có hệ thống xử lý nước thải tập trung đạt tiêu chuẩn môi trường đạt bao nhiêu phần trăm?</span></span></p>\r\n', '', 28, 1, 1656, 1084, 535, 37);
INSERT INTO `savsoft_qbank` VALUES (517, 'Nhiều lựa chọn Một câu trả lời', '<p>Đơn vị nào giải quyết các hồ sơ miễn, giảm học phí cho sinh viên tại trường Đại học Công nghệ Sài Gòn?</p>\r\n', '', 19, 1, 1596, 947, 638, 11);
INSERT INTO `savsoft_qbank` VALUES (518, 'Nhiều lựa chọn Một câu trả lời', '<p>Có bao nhiêu đối tượng miễn, giảm học phí tại STU?</p>\r\n', '', 19, 1, 1547, 746, 792, 9);
INSERT INTO `savsoft_qbank` VALUES (519, 'Nhiều lựa chọn Một câu trả lời', '<p>Những điểm mới trong công tác nộp hồ sơ miễn, giảm học phí năm học 2021-2022</p>\r\n', '', 19, 1, 1593, 909, 674, 10);
INSERT INTO `savsoft_qbank` VALUES (520, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\">Đối tượng sinh viên nào không cần xét điểm học tập khi xét miễn giảm học phí?</span></span></p>\r\n', '', 19, 1, 1540, 350, 1180, 10);
INSERT INTO `savsoft_qbank` VALUES (521, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Đối tượng Sinh viên nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></p>\r\n', '', 19, 1, 1510, 1335, 167, 8);
INSERT INTO `savsoft_qbank` VALUES (522, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 19, 1, 1532, 524, 995, 13);
INSERT INTO `savsoft_qbank` VALUES (523, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></p>\r\n', '', 38, 1, 2287, 1968, 297, 22);
INSERT INTO `savsoft_qbank` VALUES (524, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></span></span></p>\r\n', '', 38, 1, 2224, 1070, 1127, 27);
INSERT INTO `savsoft_qbank` VALUES (525, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 38, 1, 2208, 928, 1258, 22);
INSERT INTO `savsoft_qbank` VALUES (526, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></span></p>\r\n', '', 38, 1, 2237, 919, 1292, 26);
INSERT INTO `savsoft_qbank` VALUES (527, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Danh hiệu thi đua khen thưởng đối với cá nhân dành cho Sinh viên đạt thành tích học tập?</span></span></p>\r\n', '', 38, 1, 2198, 1810, 372, 16);
INSERT INTO `savsoft_qbank` VALUES (528, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xác nhận của đơn vị nào không được nhà trường công nhận khi sinh viên tham gia chương trình công tác xã hội?</span></span></p>\r\n', '', 38, 1, 2198, 1314, 864, 20);
INSERT INTO `savsoft_qbank` VALUES (529, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></span></span></p>\r\n', '', 38, 1, 2182, 915, 1253, 14);
INSERT INTO `savsoft_qbank` VALUES (530, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 38, 1, 2206, 766, 1418, 22);
INSERT INTO `savsoft_qbank` VALUES (531, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></span></p>\r\n', '', 38, 1, 2221, 1463, 740, 18);
INSERT INTO `savsoft_qbank` VALUES (532, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></span></p>\r\n', '', 38, 1, 2236, 1436, 779, 21);
INSERT INTO `savsoft_qbank` VALUES (533, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></p>\r\n', '', 38, 1, 2208, 1970, 218, 20);
INSERT INTO `savsoft_qbank` VALUES (534, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 38, 1, 2188, 960, 1206, 22);
INSERT INTO `savsoft_qbank` VALUES (535, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 38, 1, 2212, 1115, 1073, 24);
INSERT INTO `savsoft_qbank` VALUES (536, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></p>\r\n', '', 38, 1, 2227, 784, 1413, 30);
INSERT INTO `savsoft_qbank` VALUES (537, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></span></span></p>\r\n', '', 38, 1, 2165, 1957, 187, 21);
INSERT INTO `savsoft_qbank` VALUES (538, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy trình đánh giá điểm rèn luyện của sinh viên như thế nào?</span></span></p>\r\n', '', 38, 1, 2235, 1778, 429, 28);
INSERT INTO `savsoft_qbank` VALUES (539, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 38, 1, 2197, 1315, 851, 31);
INSERT INTO `savsoft_qbank` VALUES (540, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định Sinh viên đánh giá thể lực dựa trên mấy nội dung kiểm tra?</span></span></p>\r\n', '', 38, 1, 2170, 2043, 104, 23);
INSERT INTO `savsoft_qbank` VALUES (541, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 38, 1, 2167, 1985, 167, 15);
INSERT INTO `savsoft_qbank` VALUES (542, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></p>\r\n', '', 38, 1, 2269, 2046, 198, 25);
INSERT INTO `savsoft_qbank` VALUES (543, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 38, 1, 2134, 585, 1525, 24);
INSERT INTO `savsoft_qbank` VALUES (544, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 38, 1, 2175, 598, 1554, 23);
INSERT INTO `savsoft_qbank` VALUES (545, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></p>\r\n', '', 38, 1, 2149, 409, 1709, 31);
INSERT INTO `savsoft_qbank` VALUES (546, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu điều quy định về ứng xử trong bộ quy tắc ứng xử của sinh viên STU?</span></span></p>\r\n', '', 38, 1, 2232, 1118, 1081, 33);
INSERT INTO `savsoft_qbank` VALUES (547, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2214, 1817, 380, 17);
INSERT INTO `savsoft_qbank` VALUES (548, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Thực hiện nghiêm túc Quy chế đào tạo, Quy chế công tác sinh viên, Quy chế đánh giá rèn luyện sinh viên, Nội quy học đường và các Quy chế, Quy định của Bộ Giáo dục và Đào tạo và của Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2225, 1729, 479, 17);
INSERT INTO `savsoft_qbank` VALUES (549, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2242, 2054, 159, 29);
INSERT INTO `savsoft_qbank` VALUES (550, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2232, 965, 1247, 20);
INSERT INTO `savsoft_qbank` VALUES (551, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sống có trách nhiệm và tôn trọng bản thân, không làm những việc gây ảnh hưởng xấu đến danh dự của bản thân và gia đình. Có lòng tự trọng, tính trung thực, khách quan và khiêm tốn” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2236, 1992, 218, 26);
INSERT INTO `savsoft_qbank` VALUES (552, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đã đăng ký tham gia hoạt động CTXH, nhưng không thực hiện nội dung đã đăng ký không có lý do hoặc lý do không chính đáng sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 38, 1, 2211, 832, 1354, 25);
INSERT INTO `savsoft_qbank` VALUES (553, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 38, 1, 2132, 1491, 625, 16);
INSERT INTO `savsoft_qbank` VALUES (554, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\">Theo bạn, yếu tố cần có để khởi nghề thành công là gì?</span></span></p>\r\n', '', 40, 1, 1806, 1697, 101, 8);
INSERT INTO `savsoft_qbank` VALUES (555, 'Nhiều lựa chọn Một câu trả lời', '<p>Theo bạn, yếu tố cần có để  khởi nghiệp thành công là gì?</p>\r\n', '', 40, 1, 1867, 1550, 306, 11);
INSERT INTO `savsoft_qbank` VALUES (556, 'Nhiều lựa chọn Một câu trả lời', '<p>Đâu là ưu điểm khi khởi nghiệp?</p>\r\n', '', 40, 1, 1893, 1715, 173, 5);
INSERT INTO `savsoft_qbank` VALUES (557, 'Nhiều lựa chọn Một câu trả lời', '<p>Đâu là nhược điểm khi khởi nghiệp?</p>\r\n', '', 40, 1, 1841, 1661, 174, 6);
