INSERT INTO `savsoft_qbank` VALUES (587, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Phong cách của người cán bộ, đảng viên bao gồm:</span></span></p>\r\n', '', 39, 1, 1953, 1029, 909, 15);
