INSERT INTO `savsoft_qbank` VALUES (589, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 38, 1, 2161, 1436, 705, 20);
INSERT INTO `savsoft_qbank` VALUES (590, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></p>\r\n', '', 41, 1, 1314, 1100, 197, 17);
INSERT INTO `savsoft_qbank` VALUES (591, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></p>\r\n', '', 41, 1, 1348, 496, 827, 25);
INSERT INTO `savsoft_qbank` VALUES (592, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 41, 1, 1364, 270, 1071, 23);
INSERT INTO `savsoft_qbank` VALUES (593, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></span></p>\r\n', '', 41, 1, 1368, 642, 698, 28);
INSERT INTO `savsoft_qbank` VALUES (594, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Danh hiệu thi đua khen thưởng đối với cá nhân dành cho Sinh viên đạt thành tích trong học tập và rèn luyện?</span></span></p>\r\n', '', 41, 1, 1335, 1104, 212, 19);
INSERT INTO `savsoft_qbank` VALUES (595, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xác nhận của đơn vị nào không được nhà trường công nhận khi sinh viên tham gia chương trình công tác xã hội?</span></span></p>\r\n', '', 41, 1, 1392, 713, 655, 24);
INSERT INTO `savsoft_qbank` VALUES (596, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></p>\r\n', '', 41, 1, 1374, 487, 873, 14);
INSERT INTO `savsoft_qbank` VALUES (597, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 41, 1, 1315, 525, 773, 17);
INSERT INTO `savsoft_qbank` VALUES (598, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></span></p>\r\n', '', 41, 1, 1341, 679, 636, 26);
INSERT INTO `savsoft_qbank` VALUES (599, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></p>\r\n', '', 41, 1, 1330, 839, 473, 18);
INSERT INTO `savsoft_qbank` VALUES (600, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></span></span></p>\r\n', '', 41, 1, 1311, 1119, 176, 16);
INSERT INTO `savsoft_qbank` VALUES (601, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 41, 1, 1354, 407, 927, 20);
INSERT INTO `savsoft_qbank` VALUES (602, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 41, 1, 1392, 557, 813, 22);
