INSERT INTO `savsoft_qbank` VALUES (604, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></span></span></p>\r\n', '', 41, 1, 1347, 1183, 150, 14);
INSERT INTO `savsoft_qbank` VALUES (605, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy trình đánh giá điểm rèn luyện của sinh viên như thế nào?</span></span></p>\r\n', '', 41, 1, 1321, 1052, 247, 22);
INSERT INTO `savsoft_qbank` VALUES (606, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 41, 1, 1355, 596, 731, 28);
INSERT INTO `savsoft_qbank` VALUES (607, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định Sinh viên đánh giá thể lực thực hiện bao nhiêu nội dung kiểm tra?</span></span></p>\r\n', '', 41, 1, 1334, 878, 429, 27);
INSERT INTO `savsoft_qbank` VALUES (608, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 41, 1, 1352, 1084, 242, 26);
INSERT INTO `savsoft_qbank` VALUES (609, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></p>\r\n', '', 41, 1, 1365, 1214, 129, 22);
INSERT INTO `savsoft_qbank` VALUES (610, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 41, 1, 1355, 385, 949, 21);
INSERT INTO `savsoft_qbank` VALUES (611, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 41, 1, 1335, 602, 715, 18);
INSERT INTO `savsoft_qbank` VALUES (612, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></p>\r\n', '', 41, 1, 1346, 299, 1024, 23);
INSERT INTO `savsoft_qbank` VALUES (613, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong bộ quy tắc ứng xử của sinh viên STU quy định bao nhiêu điều?</span></span></p>\r\n', '', 41, 1, 1348, 678, 647, 23);
INSERT INTO `savsoft_qbank` VALUES (614, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1363, 1070, 272, 21);
INSERT INTO `savsoft_qbank` VALUES (615, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Thực hiện nghiêm túc Quy chế đào tạo, Quy chế công tác sinh viên, Quy chế đánh giá rèn luyện sinh viên, Nội quy học đường và các Quy chế, Quy định của Bộ Giáo dục và Đào tạo và của Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1401, 1085, 292, 24);
INSERT INTO `savsoft_qbank` VALUES (616, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1365, 1271, 73, 21);
INSERT INTO `savsoft_qbank` VALUES (617, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1350, 927, 402, 21);
INSERT INTO `savsoft_qbank` VALUES (618, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1339, 667, 647, 25);
INSERT INTO `savsoft_qbank` VALUES (619, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sống có trách nhiệm và tôn trọng bản thân, không làm những việc gây ảnh hưởng xấu đến danh dự của bản thân và gia đình. Có lòng tự trọng, tính trung thực, khách quan và khiêm tốn” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 41, 1, 1346, 1137, 189, 20);
INSERT INTO `savsoft_qbank` VALUES (620, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đã đăng ký tham gia hoạt động CTXH, nhưng không thực hiện nội dung đã đăng ký không có lý do hoặc lý do không chính đáng sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 41, 1, 1362, 361, 978, 23);
INSERT INTO `savsoft_qbank` VALUES (621, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></span></span></p>\r\n', '', 41, 1, 1313, 1005, 288, 20);
INSERT INTO `savsoft_qbank` VALUES (622, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy chế công tác sinh viên, có bao nhiêu nội dung vi phạm và hình thức xử lý kỷ luật đối với sinh viên?</span></span></p>\r\n', '', 41, 1, 1323, 625, 668, 30);
INSERT INTO `savsoft_qbank` VALUES (623, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo bạn dấu hiệu khác biệt trong phương pháp học đại học so với học phổ thông là gì?</span></span></p>\r\n', '', 43, 1, 2619, 2179, 427, 13);
INSERT INTO `savsoft_qbank` VALUES (624, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Khi cần tìm hiểu về một vấn đề bạn sẽ tìm thông tin ở đâu?</span></p>\r\n', '', 43, 1, 2619, 2578, 30, 11);
INSERT INTO `savsoft_qbank` VALUES (625, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Muốn học kỹ năng thì bạn cần tim 2 ở đâu?</span></span></span></p>\r\n', '', 43, 1, 2619, 1208, 1395, 16);
INSERT INTO `savsoft_qbank` VALUES (626, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Điều gì quan trọng nhất trong việc học?</span></p>\r\n', '', 43, 1, 2619, 803, 1800, 16);
INSERT INTO `savsoft_qbank` VALUES (627, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên thiếu chuyên cần sẽ bị cấm thi khi nào?</span></span></p>\r\n', '', 42, 1, 1511, 996, 506, 9);
INSERT INTO `savsoft_qbank` VALUES (628, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đại học có thời gian tối đa bao nhiêu để hoàn thành chương trình đào tạo (CTĐT)?</span></span></p>\r\n', '', 42, 1, 1549, 1352, 186, 11);
INSERT INTO `savsoft_qbank` VALUES (629, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nhà trường phân công người cố vấn và hỗ trợ sinh viên phát huy tối đa khả năng học tập, lựa chọn môn học phù hợp, theo dõi thành tivh1 học tập cho một sinh viên, nhóm sinh viên hay một lớp, gọi lả gì?</span></span></p>\r\n', '', 42, 1, 1566, 1479, 77, 10);
INSERT INTO `savsoft_qbank` VALUES (630, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong CTĐT khóa 2022, một giờ tín chỉ được quy định như thế nào?</span></span></p>\r\n', '', 42, 1, 1508, 707, 787, 14);
INSERT INTO `savsoft_qbank` VALUES (631, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối thiểu sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 42, 1, 1547, 941, 594, 12);
INSERT INTO `savsoft_qbank` VALUES (632, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Một năm học tại Trường Đại học Công nghệ Sài Gòn gồm bao nhiêu học kỳ?</span></span></span></span></p>\r\n', '', 42, 1, 1538, 1223, 309, 6);
INSERT INTO `savsoft_qbank` VALUES (633, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tại Trường Đại học Công nghệ Sài Gòn, tổng số tín chỉ cho mỗi chương trình đào tạo bậc Đại học là bao nhiêu?</span></span></p>\r\n', '', 42, 1, 1499, 838, 652, 9);
INSERT INTO `savsoft_qbank` VALUES (634, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không hoàn thành CTĐT và đã vượt quá thời gian tối đa được phép đào tạo tại trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 42, 1, 1528, 1025, 490, 13);
INSERT INTO `savsoft_qbank` VALUES (635, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xếp loại Trung bình khá được đánh giá theo thang điểm 4 là bao nhiêu?</span></span></p>\r\n', '', 42, 1, 1553, 734, 810, 9);
INSERT INTO `savsoft_qbank` VALUES (636, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Một trong những điều kiện xét tốt nghiệp, điểm trung bình chung tích luỹ của toàn khoá học đạt từ bao nhiêu điểm?</span></span></p>\r\n', '', 42, 1, 1479, 350, 1120, 9);
INSERT INTO `savsoft_qbank` VALUES (637, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối đa sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 42, 1, 1541, 626, 900, 15);
INSERT INTO `savsoft_qbank` VALUES (638, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Môn học chứa đựng nội dung kiến thức chính yếu của mỗi chương trình mà sinh viên phải tích lũy được gọi là môn học gì?</span></span></p>\r\n', '', 42, 1, 1514, 1130, 371, 13);
INSERT INTO `savsoft_qbank` VALUES (639, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công viên lịch sử văn hóa dân tộc Đền Hùng tọa lạc tại đâu?</span></span></span></span></p>\r\n', '', 44, 1, 1298, 709, 583, 6);
