INSERT INTO `savsoft_qbank` VALUES (642, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đền tưởng niệm các Vua Hùng nằm ở khu vực nào?</span></span></span></span></p>\r\n', '', 44, 1, 1313, 621, 682, 10);
INSERT INTO `savsoft_qbank` VALUES (643, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu tưởng niệm các Vua Hùng được quy hoạch gồm bao nhiêu bậc</span></span></span></span></p>\r\n', '', 44, 1, 1317, 709, 601, 7);
INSERT INTO `savsoft_qbank` VALUES (644, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu vực nào có  diện tích lớn nhất trong Công viên Lịch sử văn hóa dân tộc?</span></span></span></span></p>\r\n', '', 44, 1, 1280, 403, 869, 8);
