INSERT INTO `savsoft_qbank` VALUES (646, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu cột đá (Tầng thượng) trong khu tưởng niệm các Vua Hùng?</span></span></span></span></p>\r\n', '', 44, 1, 1305, 1156, 140, 9);
INSERT INTO `savsoft_qbank` VALUES (647, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu khối đá chủ quyền quần đảo Trường Sa được trưng bày tại Công viên lịch sử Văn hóa dân tộc?</span></span></span></span></p>\r\n', '', 44, 1, 1315, 667, 631, 17);
