INSERT INTO `savsoft_qbank` VALUES (649, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trường Đại học Công nghệ Sài Gòn được thành lập vào thời gian nào?</span></span></span></span></p>\r\n', '', 45, 1, 1290, 1198, 84, 8);
