INSERT INTO `savsoft_qbank` VALUES (695, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 48, 1, 3455, 970, 2307, 178);
INSERT INTO `savsoft_qbank` VALUES (696, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></span></p>\r\n', '', 48, 1, 3516, 1421, 1929, 166);
INSERT INTO `savsoft_qbank` VALUES (697, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Danh hiệu thi đua khen thưởng đối với cá nhân dành cho Sinh viên đạt thành tích học tập?</span></span></p>\r\n', '', 48, 1, 3525, 2744, 635, 146);
INSERT INTO `savsoft_qbank` VALUES (698, 'Nhiều lựa chọn Một câu trả lời', '<p>Xác nhận của đơn vị nào không được nhà trường công nhận khi sinh viên tham gia chương trình công tác xã hội?</p>\r\n', '', 48, 1, 3377, 2014, 1179, 184);
INSERT INTO `savsoft_qbank` VALUES (699, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></p>\r\n', '', 48, 1, 3434, 986, 2298, 150);
INSERT INTO `savsoft_qbank` VALUES (700, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 48, 1, 3487, 1169, 2181, 137);
INSERT INTO `savsoft_qbank` VALUES (701, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></span></p>\r\n', '', 48, 1, 3462, 1780, 1509, 173);
INSERT INTO `savsoft_qbank` VALUES (702, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></p>\r\n', '', 48, 1, 3485, 2781, 572, 132);
INSERT INTO `savsoft_qbank` VALUES (703, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></p>\r\n', '', 48, 1, 3463, 3071, 253, 139);
INSERT INTO `savsoft_qbank` VALUES (704, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi kết thúc hoạt động CTXH tại địa phương, SV cần nộp hồ sơ gì về nhà trường để tổng hợp ngày CTXH?</span></span></p>\r\n', '', 48, 1, 3457, 356, 2968, 133);
INSERT INTO `savsoft_qbank` VALUES (705, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 48, 1, 3549, 1462, 1914, 173);
INSERT INTO `savsoft_qbank` VALUES (706, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 48, 1, 3351, 1334, 1825, 192);
INSERT INTO `savsoft_qbank` VALUES (707, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></p>\r\n', '', 48, 1, 3470, 1131, 2174, 165);
INSERT INTO `savsoft_qbank` VALUES (708, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></p>\r\n', '', 48, 1, 3427, 3039, 234, 154);
INSERT INTO `savsoft_qbank` VALUES (709, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy trình đánh giá điểm rèn luyện của sinh viên như thế nào?</span></span></p>\r\n', '', 48, 1, 3484, 2614, 693, 177);
INSERT INTO `savsoft_qbank` VALUES (710, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 48, 1, 3494, 1856, 1464, 174);
INSERT INTO `savsoft_qbank` VALUES (711, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định Sinh viên đánh giá thể lực dựa trên mấy nội dung kiểm tra?</span></span></p>\r\n', '', 48, 1, 3402, 3149, 113, 140);
INSERT INTO `savsoft_qbank` VALUES (712, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 48, 1, 3374, 2870, 357, 147);
INSERT INTO `savsoft_qbank` VALUES (713, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></p>\r\n', '', 48, 1, 3454, 2921, 386, 147);
INSERT INTO `savsoft_qbank` VALUES (714, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 48, 1, 3444, 1158, 2094, 192);
INSERT INTO `savsoft_qbank` VALUES (715, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 48, 1, 3488, 2002, 1345, 141);
INSERT INTO `savsoft_qbank` VALUES (716, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></p>\r\n', '', 48, 1, 3500, 1116, 2159, 225);
INSERT INTO `savsoft_qbank` VALUES (717, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu điều quy định về ứng xử trong bộ quy tắc ứng xử của sinh viên STU?</span></span></p>\r\n', '', 48, 1, 3466, 1584, 1686, 196);
INSERT INTO `savsoft_qbank` VALUES (718, 'Nhiều lựa chọn Một câu trả lời', '<p>Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</p>\r\n', '', 48, 1, 3474, 2839, 489, 146);
INSERT INTO `savsoft_qbank` VALUES (719, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Thực hiện nghiêm túc Quy chế đào tạo, Quy chế công tác sinh viên, Quy chế đánh giá rèn luyện sinh viên, Nội quy học đường và các Quy chế, Quy định của Bộ Giáo dục và Đào tạo và của Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 48, 1, 3500, 2799, 535, 166);
INSERT INTO `savsoft_qbank` VALUES (720, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 48, 1, 3404, 3105, 146, 153);
INSERT INTO `savsoft_qbank` VALUES (721, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 48, 1, 3442, 2588, 705, 149);
INSERT INTO `savsoft_qbank` VALUES (722, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 48, 1, 3434, 2192, 1088, 154);
INSERT INTO `savsoft_qbank` VALUES (723, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sống có trách nhiệm và tôn trọng bản thân, không làm những việc gây ảnh hưởng xấu đến danh dự của bản thân và gia đình. Có lòng tự trọng, tính trung thực, khách quan và khiêm tốn” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 48, 1, 3435, 3004, 256, 175);
INSERT INTO `savsoft_qbank` VALUES (724, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đã đăng ký tham gia hoạt động CTXH, nhưng không thực hiện nội dung đã đăng ký không có lý do hoặc lý do không chính đáng sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 48, 1, 3461, 1227, 2080, 154);
INSERT INTO `savsoft_qbank` VALUES (725, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 48, 1, 3415, 2359, 919, 137);
INSERT INTO `savsoft_qbank` VALUES (726, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></span></p>\r\n', '', 49, 1, 1389, 1172, 176, 41);
INSERT INTO `savsoft_qbank` VALUES (727, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></p>\r\n', '', 49, 1, 1428, 385, 975, 68);
INSERT INTO `savsoft_qbank` VALUES (728, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 1, 1, 0, 0, 0, 0);
