INSERT INTO `savsoft_qbank` VALUES (737, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></p>\r\n', '', 49, 1, 1469, 1204, 214, 51);
INSERT INTO `savsoft_qbank` VALUES (738, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 49, 1, 1422, 430, 926, 66);
INSERT INTO `savsoft_qbank` VALUES (739, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></span></span></p>\r\n', '', 49, 1, 1396, 543, 773, 80);
INSERT INTO `savsoft_qbank` VALUES (740, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></p>\r\n', '', 49, 1, 1450, 616, 772, 62);
INSERT INTO `savsoft_qbank` VALUES (741, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></p>\r\n', '', 49, 1, 1399, 1248, 97, 54);
INSERT INTO `savsoft_qbank` VALUES (742, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy trình đánh giá điểm rèn luyện của sinh viên như thế nào?</span></span></p>\r\n', '', 49, 1, 1463, 1231, 179, 53);
INSERT INTO `savsoft_qbank` VALUES (743, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 49, 1, 1416, 625, 716, 75);
INSERT INTO `savsoft_qbank` VALUES (744, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định Sinh viên đánh giá thể lực dựa trên mấy nội dung kiểm tra?</span></span></p>\r\n', '', 49, 1, 1402, 945, 403, 54);
INSERT INTO `savsoft_qbank` VALUES (745, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 49, 1, 1434, 1138, 241, 55);
INSERT INTO `savsoft_qbank` VALUES (746, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></p>\r\n', '', 49, 1, 1424, 1188, 181, 55);
INSERT INTO `savsoft_qbank` VALUES (747, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 49, 1, 1414, 566, 784, 64);
INSERT INTO `savsoft_qbank` VALUES (748, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 49, 1, 1405, 937, 417, 51);
INSERT INTO `savsoft_qbank` VALUES (749, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></span></span></p>\r\n', '', 49, 1, 1431, 414, 948, 69);
INSERT INTO `savsoft_qbank` VALUES (750, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu điều trong bộ quy tắc ứng xử của sinh viên STU?</span></span></p>\r\n', '', 49, 1, 1463, 791, 586, 86);
INSERT INTO `savsoft_qbank` VALUES (751, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 49, 1, 1428, 1156, 204, 68);
INSERT INTO `savsoft_qbank` VALUES (752, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Thực hiện nghiêm túc Quy chế đào tạo, Quy chế công tác sinh viên, Quy chế đánh giá rèn luyện sinh viên, Nội quy học đường và các Quy chế, Quy định của Bộ Giáo dục và Đào tạo và của Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 49, 1, 1425, 1128, 255, 42);
INSERT INTO `savsoft_qbank` VALUES (753, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 49, 1, 1474, 1374, 52, 48);
INSERT INTO `savsoft_qbank` VALUES (754, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></p>\r\n', '', 49, 1, 1477, 1072, 345, 60);
INSERT INTO `savsoft_qbank` VALUES (755, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sống có trách nhiệm và tôn trọng bản thân, không làm những việc gây ảnh hưởng xấu đến danh dự của bản thân và gia đình. Có lòng tự trọng, tính trung thực, khách quan và khiêm tốn” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 49, 1, 1427, 1255, 126, 46);
INSERT INTO `savsoft_qbank` VALUES (757, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 49, 1, 1445, 1151, 235, 59);
INSERT INTO `savsoft_qbank` VALUES (758, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy chế công tác sinh viên, có bao nhiêu nội dung vi phạm và hình thức xử lý kỷ luật đối với sinh viên?</span></span></p>\r\n', '', 49, 1, 1447, 565, 809, 73);
INSERT INTO `savsoft_qbank` VALUES (759, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 49, 1, 1440, 790, 587, 63);
INSERT INTO `savsoft_qbank` VALUES (760, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên thiếu chuyên cần sẽ bị cấm thi khi nào?</span></span></p>\r\n', '', 50, 1, 1212, 559, 640, 13);
INSERT INTO `savsoft_qbank` VALUES (761, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đại học có thời gian tối đa bao nhiêu để hoàn thành chương trình đào tạo (CTĐT)?</span></span></p>\r\n', '', 50, 1, 1194, 938, 243, 13);
INSERT INTO `savsoft_qbank` VALUES (762, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nhà trường phân công người cố vấn và hỗ trợ sinh viên phát huy tối đa khả năng học tập, lựa chọn môn học phù hợp, theo dõi thành tích học tập cho một sinh viên, nhóm sinh viên hay một lớp, gọi lả gì?</span></span></p>\r\n', '', 50, 1, 1218, 1180, 28, 10);
INSERT INTO `savsoft_qbank` VALUES (763, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong CTĐT khóa 2023, một giờ tín chỉ được quy định như thế nào?</span></span></p>\r\n', '', 50, 1, 1170, 562, 579, 29);
INSERT INTO `savsoft_qbank` VALUES (764, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối thiểu sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 50, 1, 1236, 896, 319, 21);
INSERT INTO `savsoft_qbank` VALUES (765, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Một năm học tại Trường Đại học Công nghệ Sài Gòn gồm bao nhiêu học kỳ?</span></span></p>\r\n', '', 50, 1, 1223, 829, 382, 12);
INSERT INTO `savsoft_qbank` VALUES (766, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tại trường Đại học Công nghệ Sài Gòn, tổng số tín chỉ cho mỗi chương trình đào tạo bậc Đại học là bao nhiêu?</span></span></p>\r\n', '', 50, 1, 1204, 542, 643, 19);
INSERT INTO `savsoft_qbank` VALUES (767, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không hoàn thành CTĐT và đã vượt quá thời gian tối đa được phép đào tạo tại trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 50, 1, 1194, 846, 329, 19);
INSERT INTO `savsoft_qbank` VALUES (768, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xếp loại Trung bình khá được đánh giá theo thang điểm 4 là bao nhiêu?</span></span></p>\r\n', '', 50, 1, 1204, 641, 537, 26);
INSERT INTO `savsoft_qbank` VALUES (769, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Một trong những điều kiện xét tốt nghiệp, điểm trung bình chung tích luỹ của toàn khoá học đạt từ bao nhiêu điểm?</span></span></p>\r\n', '', 50, 1, 1193, 348, 824, 21);
INSERT INTO `savsoft_qbank` VALUES (770, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên tích lũy đủ học phần, tín chỉ quy định trong CTĐT sẽ được xét tốt nghiệp. Ngoài ra, sinh viên phải đạt chứng chỉ của môn học nào?</span></span></p>\r\n', '', 50, 1, 1224, 875, 329, 20);
INSERT INTO `savsoft_qbank` VALUES (771, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối đa sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 50, 1, 1225, 461, 734, 30);
INSERT INTO `savsoft_qbank` VALUES (772, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Môn học chứa đựng nội dung kiến thức chính yếu của mỗi chương trình mà sinh viên phải tích lũy được gọi là môn học gì?</span></span></p>\r\n', '', 50, 1, 1241, 1020, 213, 8);
INSERT INTO `savsoft_qbank` VALUES (773, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công viên lịch sử văn hóa dân tộc Đền Hùng tọa lạc tại đâu?</span></span></span></span></p>\r\n', '', 52, 1, 1251, 798, 449, 4);
INSERT INTO `savsoft_qbank` VALUES (774, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổng diện tích công viên Lịch sử văn hóa dân tộc là bao nhiêu m<sup>2</sup>?</span></span></span></span></p>\r\n', '', 52, 1, 1269, 1025, 226, 18);
INSERT INTO `savsoft_qbank` VALUES (775, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công viên lịch sử văn hóa dân tộc Đền Hùng có bao nhiêu khu vực?</span></span></span></span></p>\r\n', '', 52, 1, 1287, 1185, 98, 4);
INSERT INTO `savsoft_qbank` VALUES (776, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đền tưởng niệm các Vua Hùng nằm ở khu vực nào?</span></span></span></span></p>\r\n', '', 50, 1, 1206, 736, 451, 19);
INSERT INTO `savsoft_qbank` VALUES (777, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu tưởng niệm các Vua Hùng được quy hoạch gồm bao nhiêu bậc?</span></span></span></span></p>\r\n', '', 52, 1, 1260, 534, 704, 22);
INSERT INTO `savsoft_qbank` VALUES (778, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu vực nào có diện tích lớn nhất trong Công viên Lịch sử văn hóa dân tộc?</span></span></span></span></p>\r\n', '', 52, 1, 1266, 303, 961, 2);
INSERT INTO `savsoft_qbank` VALUES (779, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Biểu tượng trong khu tưởng niệm các Vua Hùng là gì?</span></span></span></span></p>\r\n', '', 52, 1, 1289, 777, 505, 7);
INSERT INTO `savsoft_qbank` VALUES (780, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu cột đá (Tầng thượng) trong khu tưởng niệm các Vua Hùng?</span></span></span></span></p>\r\n', '', 52, 1, 1301, 1188, 106, 7);
INSERT INTO `savsoft_qbank` VALUES (781, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu khối đá chủ quyền quần đảo Trường Sa được trưng bày tại Công viên lịch sử Văn hóa dân tộc?</span></span></span></span></p>\r\n', '', 52, 1, 1274, 927, 336, 11);
