INSERT INTO `savsoft_qbank` VALUES (789, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để liên hệ các hoạt động về nghiên cứu khoa học, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n', '', 51, 1, 1322, 404, 897, 21);
INSERT INTO `savsoft_qbank` VALUES (790, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để liên hệ hỗ trợ các giấy xác nhận cho sinh viên như hoãn nghĩa vụ quân sự, vay vốn… sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n', '', 51, 1, 1302, 851, 442, 9);
INSERT INTO `savsoft_qbank` VALUES (791, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để liên hệ hỗ trợ các vấn đề về bảo hiểm y tế, sinh viên cần liên hệ phòng ban nào?</span></span></p>\r\n', '', 51, 1, 1342, 389, 935, 18);
INSERT INTO `savsoft_qbank` VALUES (792, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để làm các hồ sơ về giảm học phí, học bổng, sinh viên cần liên hệ phòng ban nào?</span></span></p>\r\n', '', 51, 1, 1282, 750, 510, 22);
INSERT INTO `savsoft_qbank` VALUES (793, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để tham gia các hoạt động tình nguyện, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n', '', 51, 1, 1295, 393, 893, 9);
INSERT INTO `savsoft_qbank` VALUES (794, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tiền thân trường Đại học công nghệ Sài Gòn là trường nào?</span></span></span></span></p>\r\n', '', 51, 1, 1300, 962, 327, 11);
INSERT INTO `savsoft_qbank` VALUES (795, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Triết lý giáo dục của Trường Đại học Công nghệ Sài Gòn là gì?</span></span></span></span></p>\r\n', '', 51, 1, 1272, 883, 379, 10);
INSERT INTO `savsoft_qbank` VALUES (796, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trường ĐH Công nghệ Sài Gòn đã có bao nhiêu khoa đạt được kiểm định chất lượng giáo dục theo chuẩn AUN-QA?</span></span></span></span></p>\r\n', '', 51, 1, 1306, 365, 932, 9);
INSERT INTO `savsoft_qbank` VALUES (798, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo Hồ Chí Minh, cách mạng giải phóng dân tộc phải đi theo con đường nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1543, 1302, 24, 217);
INSERT INTO `savsoft_qbank` VALUES (799, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nguyễn Tất Thành đã từng dạy học ở ngôi trường nào trước khi ra đi tìm đường cứu nước?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1542, 1178, 143, 221);
INSERT INTO `savsoft_qbank` VALUES (800, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Luận cương của V. I. Lênin làm cho tôi rất cảm động, phấn khởi, sáng tỏ, tin tưởng biết bao. Tôi vui mừng đến phát khóc lên. Ngồi một mình trong buồng mà tôi nói to lên như đang nói trước quần chúng đông đảo: Hỡi đồng bào bị đọa đày đau khổ? Đây là cái cần thiết cho chúng ta, đây là con đường giải phóng của chúng ta”. Nguyễn Ái Quốc nói câu ấy khi đang ở đâu?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1564, 806, 468, 290);
INSERT INTO `savsoft_qbank` VALUES (801, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Chủ tịch Hồ Chí Minh sinh vào năm nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1531, 1281, 30, 220);
INSERT INTO `savsoft_qbank` VALUES (802, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nguyễn Ái Quốc đọc “Sơ thảo lần thứ nhất Luận cương về vấn đề dân tộc và vấn đề thuộc địa” của V.I.Lênin vào thời gian nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1511, 1238, 75, 198);
INSERT INTO `savsoft_qbank` VALUES (803, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nguyễn Tất Thành ra đi tìm đường cứu nước tại bến cảng Nhà Rồng Sài Gòn vào thời gian nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1589, 1252, 87, 250);
INSERT INTO `savsoft_qbank` VALUES (804, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Cũng như ngọc càng mài càng sáng, vàng càng luyện càng trong”. Câu trên ở tác phẩm nào của Hồ Chí Minh?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1625, 604, 757, 264);
INSERT INTO `savsoft_qbank` VALUES (805, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Tất cả các dân tộc trên thế giới đều sinh ra bình đẳng, dân tộc nào cũng có quyền sống, quyền sung sướng và quyền tự do”. Câu trên Hồ Chí Minh nói đó trong tác phẩm nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1609, 1252, 91, 266);
INSERT INTO `savsoft_qbank` VALUES (806, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Toàn thể dân tộc Việt Nam quyết đem tất cả tinh thần và lực lượng, tính mạng và của cải để giữ vững quyền tự do, độc lập ấy”. Đoạn văn trên trích từ bài viết nào của chủ tịch Hồ Chí Minh?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1518, 974, 289, 255);
INSERT INTO `savsoft_qbank` VALUES (807, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\">Chọn cụm từ đúng điền vào chỗ trống: “Toàn thể dân tộc Việt Nam quyết đem …… để giữ vững quyền tự do, độc lập ấy”.</span></strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"></p>\r\n', '', 53, 1, 850, 726, 67, 57);
INSERT INTO `savsoft_qbank` VALUES (808, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Ham muốn tột bậc của chủ tịch Hồ Chí Minh là gì khi Người trả lời các nhà báo nước ngoài vào đầu năm 1946, sau thắng lợi của cuộc tổng tuyển cử đầu tiên của nước Việt Nam độc lập?</span></span></strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\">​​​​​​​</p>\r\n', '', 53, 1, 1567, 1200, 95, 272);
INSERT INTO `savsoft_qbank` VALUES (809, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo Hồ Chí Minh, “giặc nội xâm” bao gồm những loại nào?</span></span></strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"></p>\r\n', '', 53, 1, 1653, 1345, 33, 275);
INSERT INTO `savsoft_qbank` VALUES (810, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Luận điểm: “Đạo đức cách mạng không phải trên trời sa xuống. Nó do đấu tranh, rèn luyện bền bỉ hằng ngày mà phát triển và củng cố. Cũng như ngọc càng mài càng sáng, vàng càng luyện càng trong” là của ai?</span></span></strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"></p>\r\n', '', 53, 1, 1572, 1274, 68, 230);
INSERT INTO `savsoft_qbank` VALUES (811, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo chủ tịch Hồ Chí Minh, học để làm gì?</span></span></strong></span></span></p>\r\n\r\n<p></p>\r\n', '', 53, 1, 1581, 953, 348, 280);
INSERT INTO `savsoft_qbank` VALUES (812, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Chủ tịch Hồ Chí Minh ví tuổi trẻ như mùa nào trong năm?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1637, 1344, 32, 261);
INSERT INTO `savsoft_qbank` VALUES (813, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tác phẩm nào sau đây không phải là của chủ tịch Hồ Chí Minh?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1554, 1094, 218, 242);
INSERT INTO `savsoft_qbank` VALUES (814, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tư tưởng Hồ Chí Minh được hình thành từ những nguồn gốc nào?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1614, 1247, 103, 264);
INSERT INTO `savsoft_qbank` VALUES (815, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo giáo trình Tư tưởng Hồ Chí Minh, có mấy chuẩn mực đạo đức cách mạng?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1567, 236, 1058, 273);
