INSERT INTO `savsoft_qbank` VALUES (818, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Học tập, vận dụng và phát triển tư tưởng Hồ Chí Minh cần nắm vững phương pháp luận nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1628, 1234, 116, 278);
INSERT INTO `savsoft_qbank` VALUES (819, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Cơ chế vận hành của hệ thống chính trị nước ta là gì?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1519, 1004, 275, 240);
INSERT INTO `savsoft_qbank` VALUES (820, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đoàn Thanh niên Cộng sản Hồ Chí Minh tổ chức và hoạt động theo nguyên tắc nào?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1543, 989, 290, 264);
INSERT INTO `savsoft_qbank` VALUES (821, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi được thành lập, Đoàn Thanh niên Cộng sản Hồ Chí Minh có tên là gì?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1560, 817, 525, 218);
INSERT INTO `savsoft_qbank` VALUES (822, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Bài ca chính thức của Đoàn (Đoàn ca) Thanh niên Cộng sản Hồ Chí Minh có tên là gì?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1550, 1106, 209, 235);
INSERT INTO `savsoft_qbank` VALUES (823, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Đoàn viên và thanh niên ta nói chung là tốt, mọi việc đều hăng hái xung phong, không ngại khó khăn, có chí tiến thủ. Đảng ta cần chăm lo giáo dục đạo đức cách mạng cho họ, đào tạo họ thành những người thừa kế xây dựng chủ nghĩa xã hội vừa hồng, vừa chuyên. Bồi dưỡng thế hệ cách mạng cho đời sau là một việc rất quan trọng và rất cần thiết”. Đoạn văn trên được trích trong tác phẩm nào của chủ tịch Hồ Chí Minh?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1555, 961, 356, 238);
INSERT INTO `savsoft_qbank` VALUES (824, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Ngày truyền thống của sinh viên học sinh Việt Nam là ngày nào?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1518, 1208, 94, 216);
INSERT INTO `savsoft_qbank` VALUES (825, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Ngày 9/1/1950, Đoàn Thanh niên cứu quốc và Đoàn học sinh-sinh viên Sài Gòn - Chợ Lớn đã vận động và tổ chức hơn 2.000 HSSV và 7.000 nhân dân Sài Gòn - Chợ Lớn biểu tình đòi đảm bảo an ninh cho học sinh sinh viên, trả tự do cho những sinh viên-học sinh bị bắt và mở lại trường học. Một học sinh ưu tú đã ngã xuống trong cuộc đấu tranh này, đó là ai?</span></span></strong></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1574, 1122, 200, 252);
INSERT INTO `savsoft_qbank` VALUES (826, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Chủ tịch Hồ Chí Minh đọc Tuyên ngôn độc lập, khai sinh nước Việt Nam dân chủ cộng hòa vào ngày tháng năm nào?</span></span></strong></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1596, 1272, 79, 245);
INSERT INTO `savsoft_qbank` VALUES (827, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Chiến dịch Điện Biên Phủ kết thúc vào ngày tháng năm nào?</span></span></strong></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1614, 1295, 85, 234);
INSERT INTO `savsoft_qbank` VALUES (828, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Chiến dịch Hồ Chí Minh kết thúc vào ngày tháng năm nào?</span></span></strong></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1553, 1253, 85, 215);
INSERT INTO `savsoft_qbank` VALUES (829, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Tính đến năm 2024, </span></span></strong><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Việt Nam được Đại hội đồng Liên hợp quốc bầu làm ủy viên không thường trực Hội đồng Bảo an Liên hợp quốc bao nhiêu lần<strong>?</strong></span></span></span></strong></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1644, 1120, 234, 290);
INSERT INTO `savsoft_qbank` VALUES (830, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Con đường của thanh niên chỉ là con đường cách mạng, không thể có con đường nào khác”. Câu nói trên của ai?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1570, 1245, 91, 234);
INSERT INTO `savsoft_qbank` VALUES (831, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Chủ tịch Hồ Chí Minh ra đi tìm đường cứu nước tại bến cảng Nhà Rồng lúc bao nhiêu tuổi?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1548, 1233, 112, 203);
INSERT INTO `savsoft_qbank` VALUES (832, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Một dân tộc, một đảng và mỗi con người, ngày hôm qua là vĩ đại, có sức hấp dẫn lớn, không nhất định hôm nay và ngày mai vẫn được mọi người yêu mến và ca ngợi, nếu lòng dạ không trong sáng nữa, nếu sa vào ………….”. Thêm vào chỗ trống cụm từ nào sau đây?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1620, 1089, 261, 270);
INSERT INTO `savsoft_qbank` VALUES (833, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“Tư tưởng bảo thủ là như những sợi dây cột chân cột tay người ta, phải vất nó đi. Muốn tiến bộ thì phải có tinh thần mạnh dạn, ………….”. Thêm vào chỗ trống cụm từ nào sau đây?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1573, 1059, 271, 243);
INSERT INTO `savsoft_qbank` VALUES (834, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Ngày thành lập Đoàn Thanh niên Cộng sản Hồ Chí Minh là ngày nào?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1612, 1250, 127, 235);
INSERT INTO `savsoft_qbank` VALUES (835, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Hệ thống chính trị Việt Nam có bao nhiêu thành viên?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1502, 199, 1054, 249);
INSERT INTO `savsoft_qbank` VALUES (836, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Tổ chức nào sau đây không phải là thành viên của hệ thống chính trị Việt Nam?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1599, 958, 377, 264);
INSERT INTO `savsoft_qbank` VALUES (837, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Theo Hiến pháp nước Cộng hòa xã hội chủ nghĩa Việt Nam (2013), Đoàn Thanh niên Cộng sản Hồ Chí Minh được quy định là tổ chức nào?</span></span></strong></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1546, 1107, 173, 266);
INSERT INTO `savsoft_qbank` VALUES (838, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:black\">Theo Hiến pháp nước Cộng hòa xã hội chủ nghĩa Việt Nam (2013), nước ta có bao nhiêu tổ chức chính trị - xã hội?</span></span></strong></span></span></p>\r\n', '', 53, 1, 1549, 987, 313, 249);
INSERT INTO `savsoft_qbank` VALUES (839, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><em><strong><span style=\"font-size:13.0pt\"><span style=\"color:#333333\">“Hỡi đồng bào toàn quốc! Chúng ta muốn hòa bình, chúng ta phải nhân nhượng. Nhưng chúng ta càng nhân nhượng, thực dân Pháp càng lấn tới, vì chúng quyết tâm cướp nước ta một lần nữa! Không! Chúng ta thà hy sinh tất cả, chứ nhất định không chịu mất nước, nhất định không chịu làm nô lệ”. Được trích trong tác phẩm nào của chủ tịch Hồ Chí Minh?</span></span></strong></em></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1503, 1130, 156, 217);
INSERT INTO `savsoft_qbank` VALUES (840, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:12pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,sans-serif\"><em><strong><span style=\"font-size:13.0pt\"><span style=\"color:#333333\">“Không có gì quý hơn độc lập tự do!”. Đó là câu nói của ai?</span></span></strong></em></span></span></span>​​​​​​​</p>\r\n', '', 53, 1, 1599, 1361, 10, 228);
INSERT INTO `savsoft_qbank` VALUES (841, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></p>\r\n', '', 54, 1, 3123, 1037, 1845, 241);
INSERT INTO `savsoft_qbank` VALUES (842, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 54, 1, 3148, 1022, 2006, 120);
INSERT INTO `savsoft_qbank` VALUES (843, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></span></p>\r\n', '', 54, 1, 3080, 1093, 1833, 154);
INSERT INTO `savsoft_qbank` VALUES (844, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></span></span></p>\r\n', '', 54, 1, 3165, 956, 2074, 135);
INSERT INTO `savsoft_qbank` VALUES (845, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 54, 1, 3077, 1451, 1472, 154);
INSERT INTO `savsoft_qbank` VALUES (846, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></span></p>\r\n', '', 54, 1, 3062, 1578, 1326, 158);
INSERT INTO `savsoft_qbank` VALUES (847, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></p>\r\n', '', 54, 1, 3115, 2728, 283, 104);
INSERT INTO `savsoft_qbank` VALUES (848, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></p>\r\n', '', 54, 1, 3120, 2779, 196, 145);
INSERT INTO `savsoft_qbank` VALUES (849, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi kết thúc hoạt động CTXH tại địa phương, SV cần nộp hồ sơ gì về nhà trường để tổng hợp ngày CTXH?</span></span></p>\r\n', '', 54, 1, 3131, 116, 2872, 143);
INSERT INTO `savsoft_qbank` VALUES (850, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 54, 1, 3053, 1198, 1672, 183);
INSERT INTO `savsoft_qbank` VALUES (851, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 54, 1, 3136, 1588, 1407, 141);
INSERT INTO `savsoft_qbank` VALUES (852, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></p>\r\n', '', 54, 1, 3084, 1001, 1940, 143);
INSERT INTO `savsoft_qbank` VALUES (853, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></p>\r\n', '', 54, 1, 3103, 2806, 156, 141);
INSERT INTO `savsoft_qbank` VALUES (854, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 54, 1, 3167, 1688, 1337, 142);
INSERT INTO `savsoft_qbank` VALUES (855, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 54, 1, 3090, 2808, 156, 126);
INSERT INTO `savsoft_qbank` VALUES (856, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo <span style=\"color:#2e0df3\">Nội - Ngoại</span> trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 54, 1, 3143, 1618, 1405, 120);
INSERT INTO `savsoft_qbank` VALUES (857, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"color:null\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không khai báo Nội - Ngoại Ngoại trú sẽ bị xử lý như thế nào?</span></span></span></p>\r\n', '', 54, 1, 3150, 1124, 1878, 148);
INSERT INTO `savsoft_qbank` VALUES (858, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu điều quy định về ứng xử trong bộ quy tắc ứng xử của sinh viên STU?</span></span></p>\r\n', '', 54, 1, 3131, 1339, 1601, 191);
INSERT INTO `savsoft_qbank` VALUES (859, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 54, 1, 3068, 2540, 382, 146);
INSERT INTO `savsoft_qbank` VALUES (860, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 54, 1, 3110, 2895, 70, 145);
INSERT INTO `savsoft_qbank` VALUES (861, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 54, 1, 3118, 2347, 587, 184);
INSERT INTO `savsoft_qbank` VALUES (862, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 54, 1, 3065, 2101, 797, 167);
INSERT INTO `savsoft_qbank` VALUES (863, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đã đăng ký tham gia hoạt động CTXH, nhưng không thực hiện nội dung đã đăng ký không có lý do hoặc lý do không chính đáng sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 54, 1, 3130, 1333, 1652, 145);
INSERT INTO `savsoft_qbank` VALUES (864, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 54, 1, 3090, 2128, 840, 122);
INSERT INTO `savsoft_qbank` VALUES (865, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên thực hiện xác nhận sinh viên tại đâu?</span></span></p>\r\n', '', 54, 1, 3096, 399, 2562, 135);
INSERT INTO `savsoft_qbank` VALUES (866, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“<em>Hoạt động phục vụ cộng đồng</em>” được hiểu như thế nào?</span></span></p>\r\n', '', 54, 1, 3039, 1679, 1215, 145);
INSERT INTO `savsoft_qbank` VALUES (867, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Phạm vi phục vụ cộng đồng của STU?</span></span></p>\r\n', '', 54, 1, 3129, 2303, 641, 185);
INSERT INTO `savsoft_qbank` VALUES (868, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> Kết nối và phục vụ cộng đồng trong hoạt động tình nguyện, công tác xã hội bao gồm những nội dung gì?</span></span></p>\r\n', '', 54, 1, 3066, 2552, 371, 143);
INSERT INTO `savsoft_qbank` VALUES (869, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Kết nối và phục vụ cộng đồng trong hoạt động hỗ trợ người học bao gồm nội dung gì?</span></span></p>\r\n', '', 54, 1, 3072, 2575, 332, 165);
INSERT INTO `savsoft_qbank` VALUES (870, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Quy định kết nối & phục vụ cộng đồng STU không áp dụng cho đối tượng nào?</span></p>\r\n', '', 54, 1, 1732, 1532, 157, 43);
INSERT INTO `savsoft_qbank` VALUES (871, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của Quy định kết nối & phục vụ cộng đồng STU là gì?</span></span></p>\r\n', '', 54, 1, 3127, 2027, 916, 184);
INSERT INTO `savsoft_qbank` VALUES (872, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xây dựng cơ chế phối hợp, tạo điều kiện để người học được tham gia các hoạt động về chuyên môn, hoạt động ngoại khoá, văn hóa, văn nghệ, thể dục thể thao, câu lạc bộ học thuật với các bên liên quan, thuộc nội dung nào trong quy chế kết nối và phục vụ cộng đồng?</span></span></p>\r\n', '', 54, 1, 3060, 1258, 1568, 234);
INSERT INTO `savsoft_qbank` VALUES (873, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổ chức các hoạt động tình nguyện cụ thể: thăm gia đình chính  sách có công với cách mạng, hiến máu nhân đạo, quyên góp ủng hộ quỹ vì người nghèo, ủng hộ đồng bào thiên tai lũ lụt, trao học bổng … các hoạt động phối hợp cùng với địa phương chăm lo an sinh xã hội, thuộc nội dung trong quy chế kết nối và phục vụ cộng đồng?</span></span></p>\r\n', '', 54, 1, 3148, 2647, 331, 170);
INSERT INTO `savsoft_qbank` VALUES (874, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tạo môi trường, mạng lưới thúc đẩy nghiên cứu khoa học sinh viên, học viên nhằm nâng cao năng lực nghiên cứu, tư duy phân tích, ứng dụng lý thuyết của người học. thuộc nội dung trong quy chế kết nối và phục vụ cộng đồng?</span></span></p>\r\n', '', 54, 1, 3070, 2331, 555, 184);
INSERT INTO `savsoft_qbank` VALUES (875, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổ chức thực hiện quy định ngày công tác xã hội đối với sinh viên STU thuộc nội dung trong quy chế kết nối và phục vụ cộng đồng?</span></span></p>\r\n', '', 54, 1, 3102, 2390, 528, 184);
INSERT INTO `savsoft_qbank` VALUES (876, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> theo dõi kết quả điểm rèn luyện, sinh viên xem tại đâu?</span></span></p>\r\n', '', 54, 1, 3105, 2352, 637, 116);
INSERT INTO `savsoft_qbank` VALUES (877, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đối tượng nào sau đây không thuộc diện xét miễn giảm học phí tại trường?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (878, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu đối tượng Sinh viên được xét giảm học phí tại trường?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (879, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với Sinh viên là từ bao nhiêu điểm?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (880, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Điểm trung bình ở học kỳ hoặc năm học trước để xét giảm học phí đối với đối tượng anh, chị em ruột đang học tại trường là từ bao nhiêu điểm? </span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (881, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Danh hiệu thi đua khen thưởng đối với cá nhân dành cho Sinh viên đạt thành tích học tập?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (882, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xác nhận của đơn vị nào không được nhà trường công nhận khi sinh viên tham gia chương trình công tác xã hội?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (883, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên chưa hoàn thành đủ số ngày công tác xã hội sẽ bị xử lý thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (884, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sau khi có kết quả số ngày CTXH tạm thời sinh viên có bao nhiêu ngày để thực hiện quyền khiếu nại?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (885, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định quy đổi ngày CTXH, Sinh viên thực hiện công việc từ bao nhiêu giờ thì được tính 1 ngày CTXH?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (886, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong toàn khóa học Sinh viên hệ Đại học phải tích lũy đủ bao nhiêu ngày CTXH?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (887, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trước khi tham gia hoạt động CTXH tại địa phương, SV cần phải làm gì?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (888, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SV có bao nhiêu thời gian để thực hiện tổng hợp và nộp hồ sơ CTXH tại địa phương sau khi kết thúc chương trình?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (889, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định đánh giá kết quả rèn luyện có bao nhiêu nội dung?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (890, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Thời gian khiếu nại kết quả rèn luyện đối với Sinh viên hệ Đại học trong thời hạn bao nhiêu ngày kể từ ngày công bố kết quả tạm thời?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (891, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đánh giá điểm rèn luyện dựa trên các yếu tố nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (892, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy trình đánh giá điểm rèn luyện của sinh viên như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (893, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không tham gia hoặc không đạt tiêu chuẩn đánh giá thể lực lần 2 sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (894, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy định Sinh viên đánh giá thể lực dựa trên mấy nội dung kiểm tra?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (895, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không thực hiện khám sức khỏe định kỳ hàng năm sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (896, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của việc Sinh viên khai báo Ngoại trú là gì?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (897, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không khai báo Nội - Ngoại Ngoại trú sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (898, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi có sự thay đổi về nơi cư trú, sinh viên phải báo địa chỉ nơi cư trú của mình với nhà trường trong thời hạn bao nhiêu ngày?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (899, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên khai báo Ngoại trú bao nhiêu lần trong năm học?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (900, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu danh hiệu khen thưởng đối với tập thể lớp sinh viên?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (901, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu điều trong bộ quy tắc ứng xử của sinh viên STU?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (902, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sinh viên phải chấp hành đúng nội quy, quy định của Trường và đơn vị, có trách nhiệm giữ gìn vệ sinh, cảnh quan, môi trường góp phần xây dựng nếp sống văn minh, Trường xanh, sạch, đẹp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (903, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Thực hiện nghiêm túc Quy chế đào tạo, Quy chế công tác sinh viên, Quy chế đánh giá rèn luyện sinh viên, Nội quy học đường và các Quy chế, Quy định của Bộ Giáo dục và Đào tạo và của Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (904, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Kính trọng, lễ phép, đúng mực với giảng viên, cán bộ, nhân viên trong trường. Thái độ chào hỏi, ngôn ngữ trong xưng hô thể hiện sự “Tôn sư – Trọng đạo”. Nghiêm cấm sử dụng các trang mạng xã hội, trang thông tin điện tử, diễn đàn mạng để đăng tin và bình luận không mang tính xây dựng về Nhà trường; phán xét, nhận định không đúng sự thật theo chiều hướng tiêu cực đối với giảng viên, cán bộ, nhân viên Nhà trường” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (905, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Có ý thức giữ gìn bản sắc văn hóa ứng xử của dân tộc, giữ gìn sự trong sáng của tiếng Việt khi giao tiếp trên mạng xã hội. Không nên dùng từ ngữ tục tĩu hoặc từ lạ không có trong từ điển tiếng Việt, không nên dùng tiếng lóng, từ viết tắt hoặc ngôn ngữ pha tạp” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (906, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công viên lịch sử văn hóa dân tộc Đền Hùng tọa lạc tại đâu?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (907, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổng diện tích công viên Lịch sử văn hóa dân tộc là bao nhiêu m<sup>2</sup>?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (908, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công viên lịch sử văn hóa dân tộc Đền Hùng có bao nhiêu khu vực?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (909, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đền tưởng niệm các Vua Hùng nằm ở khu vực nào?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (910, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu tưởng niệm các Vua Hùng được quy hoạch gồm bao nhiêu bậc</span></span></span></span>?</p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (911, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khu vực nào có  diện tích lớn nhất trong Công viên Lịch sử văn hóa dân tộc</span></span></span></span>?</p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (912, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Biểu tượng trong khu tưởng niệm các Vua Hùng là gì</span></span></span></span>?</p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (913, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu cột đá (Tầng thượng) trong khu tưởng niệm các Vua Hùng?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (914, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Có bao nhiêu khối đá chủ quyền quần đảo Trường Sa được trưng bày tại Công viên lịch sử Văn hóa dân tộc?</span></span></span></span></p>\r\n', '', 58, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (915, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nhà bia được xây dựng tại đâu</span></span></span></span>?</p>\r\n', '', 58, 1, 0, 0, 0, 0);
