INSERT INTO `savsoft_qbank` VALUES (921, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nguồn học liệu mở (OER) nào sau đây phổ biến tại Việt Nam?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (922, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tại sao việc kiểm tra độ tin cậy của thông tin lại cần thiết?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (923, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nguồn thông tin nào được coi là đáng tin cậy nhất?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (924, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">AI có thể hỗ trợ gì trong quá trình khai thác thông tin học tập?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (925, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công cụ AI nào dưới đây phổ biến và hỗ trợ sinh viên khi viết báo cáo?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (926, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Phương pháp ghi chú nào giúp sinh viên tổ chức thông tin tốt hơn?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (927, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công cụ nào dưới đây giúp quản lý và chia sẻ tài liệu học tập nhóm?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (928, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tại sao phân loại tài liệu theo nhu cầu học tập lại quan trọng?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (929, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Khi sử dụng thông tin từ nguồn khác, sinh viên cần làm gì để không vi phạm bản quyền?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (930, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Công cụ nào sau đây giúp kiểm tra đạo văn trong bài viết?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (931, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Kỹ năng tự học giúp sinh viên như thế nào?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (932, 'Nhiều lựa chọn Một câu trả lời', '<h1 style=\"margin-left:43.35pt; margin-right:0cm; text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Ứng dụng ghi chú nào sau đây giúp sinh viên tổ chức tài liệu hiệu quả?</span></span></h1>\r\n', '', 57, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (933, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Không sử dụng hệ thống đào tạo trực tuyến làm nơi thảo luận, truyền bá các thông tin không lành mạnh, phản động, chống lại đường lối, chính sách của Đảng và nhà nước Việt Nam, vi phạm thuần phong mỹ tục của dân tộc Việt Nam, các thông tin xâm phạm đến đời tư của các thành viên trong lớp học, các thông tin đưa lên với mục đích kiện cáo, bôi nhọ, gây dư luận…” thuộc quy tắc ứng xử nào?</span></span></span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (934, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nội dung “Sống có trách nhiệm và tôn trọng bản thân, không làm những việc gây ảnh hưởng xấu đến danh dự của bản thân và gia đình. Có lòng tự trọng, tính trung thực, khách quan và khiêm tốn” thuộc quy tắc ứng xử nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (935, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đã đăng ký tham gia hoạt động CTXH, nhưng không thực hiện nội dung đã đăng ký không có lý do hoặc lý do không chính đáng sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (936, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký hoạt động CTXH nhưng không hoàn thành nhiệm vụ và gây ảnh hưởng đến hoạt động, tổ chức, nhà trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (937, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Theo quy chế công tác sinh viên, có bao nhiêu nội dung vi phạm và hình thức xử lý kỷ luật đối với sinh viên?</span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (938, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">“<em>Hoạt động phục vụ cộng đồng</em>” được hiểu là gì?</span></span></strong></span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (939, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Phạm vi phục vụ cộng đồng của STU là gì?</span></span></strong></span></span></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (940, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Kết nối và phục vụ cộng đồng trong hoạt động tình nguyện, công tác xã hội bao gồm những gì?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (941, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Kết nối và phục vụ cộng đồng trong hoạt động hỗ trợ người học gồm nội dung gì?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (942, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Quy định kết nối & phục vụ cộng đồng STU không được áp dụng đối tượng nào?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (943, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Mục đích của Quy định kết nối & phục vụ cộng đồng STU là gì?</span></span></strong></p>\r\n\r\n<p></p>\r\n\r\n<ol style=\"list-style-type:lower-alpha\">\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tăng cường mối quan hệ gắn bó giữa Nhà trường với doanh nghiệp, địa phương; quảng bá hình ảnh Nhà   trường có sức lan tỏa trong cộng đồng, xã hội;</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nâng cao vai trò, ý thức và trách nhiệm của Nhà trường, các đơn vị, tổ chức, đoàn thể trực thuộc, Giảng viên, Cán bộ nhân viên, người học và các bên liên quan trong hoạt động kết nối và phục vụ cộng đồng.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Đáp án a</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:red\">Đáp án a & b</span></span></span></span></span></li>\r\n</ol>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (944, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xây dựng cơ chế phối hợp, tạo điều kiện để người học được tham gia các hoạt động về chuyên môn, hoạt động ngoại khoá, văn hóa, văn nghệ, thể dục thể thao, câu lạc bộ học thuật với các bên liên quan, thuộc nội dung nào trong quy chế?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (945, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổ chức các hoạt động tình nguyện cụ thể: thăm gia đình chính  sách có công với cách mạng, hiến máu nhân đạo, quyên góp ủng hộ quỹ vì người nghèo, ủng hộ đồng bào thiên tai lũ lụt, trao học bổng … các hoạt động phối hợp cùng với địa phương chăm lo an sinh xã hội </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">, thuộc nội dung nào trong quy chế Kết nối và phục vụ cộng đồng?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (946, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tạo môi trường, mạng lưới thúc đẩy nghiên cứu khoa học sinh viên, học viên nhằm nâng cao năng lực nghiên cứu, tư duy phân tích, ứng dụng lý thuyết của người học. </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">thuộc nội dung nào trong quy chế Kết nối và phục vụ cộng đồng?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (947, 'Nhiều lựa chọn Một câu trả lời', '<p><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tổ chức thực hiện quy định ngày công tác xã hội đối với sinh viên STU </span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">thuộc nội dung nào trong quy chế Kết nối và phục vụ  cộng đồng?</span></span></strong></p>\r\n', '', 55, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (948, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên thiếu chuyên cần sẽ bị cấm thi khi nào?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (949, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đại học có thời gian tối đa bao nhiêu để hoàn thành chương trình đào tạo (CTĐT)?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (950, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Nhà trường phân công người cố vấn và hỗ trợ sinh viên phát huy tối đa khả năng học tập, lựa chọn môn học phù hợp, theo dõi thành tích học tập cho một sinh viên, nhóm sinh viên hay một lớp, gọi lả gì?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (951, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trong CTĐT khóa 2023, một giờ tín chỉ được quy định như thế nào?</span></span></span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (952, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối thiểu sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (953, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Một năm học tại Trường Đại học Công nghệ Sài Gòn gồm bao nhiêu học kỳ?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (954, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tại trường Đại học Công nghệ Sài Gòn, tổng số tín chỉ cho mỗi chương trình đào tạo bậc Đại học là bao nhiêu?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (955, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên không hoàn thành CTĐT và đã vượt quá thời gian tối đa được phép đào tạo tại trường sẽ bị xử lý như thế nào?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (956, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Xếp loại Trung bình khá được đánh giá theo thang điểm 4 là bao nhiêu?</span></span></span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (957, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Một trong những điều kiện xét tốt nghiệp, điểm trung bình chung tích luỹ của toàn khoá học đạt từ bao nhiêu điểm?</span></p>\r\n\r\n<p></p>\r\n\r\n<p style=\"margin-left:0cm; margin-right:0cm; text-align:justify\"></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (958, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\">Sinh viên tích lũy đủ học phần, tín chỉ quy định trong CTĐT sẽ được xét tốt nghiệp. Ngoài ra, sinh viên phải đạt chứng chỉ của môn học nào?</span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (959, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên đăng ký môn học để học tập học kỳ tiếp theo. Số tín chỉ tối đa sinh viên có thể đăng ký trong học kỳ chính là bao nhiêu?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (960, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Môn học chứa đựng nội dung kiến thức chính yếu của mỗi chương trình mà sinh viên phải tích lũy được gọi là môn học gì?</span></span></p>\r\n', '', 56, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (961, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trường Đại học Công nghệ Sài Gòn được thành lập vào thời gian nào?</span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (962, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trường hiện tại có bao nhiêu khoa đào tạo?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (963, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Slogan của trường là gì?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (964, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sứ mệnh của nhà trường là gì?</span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (965, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để làm các thủ tục về học vụ, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n\r\n<p></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (966, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để liên hệ các hoạt động về nghiên cứu khoa học, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n\r\n<ol>\r\n	<li style=\"list-style-type:none\">\r\n	<ol style=\"list-style-type:lower-alpha\">\r\n		<li style=\"list-style-type:none\"></li>\r\n	</ol>\r\n	</li>\r\n</ol>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (967, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sinh viên thực hiện xác nhận sinh viên online như hoãn nghĩa vụ quân sự, vay vốn ngân hàng chính sách xã hội, giảm trừ gia cảnh, … tại đâu?</span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (968, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để liên hệ hỗ trợ các vấn đề về bảo hiểm y tế, sinh viên cần liên hệ phòng ban nào?</span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (969, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:0cm; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để làm các hồ sơ về giảm học phí, học bổng, sinh viên cần liên hệ phòng ban nào?</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0cm; margin-right:0cm\"></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (970, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để tham gia các hoạt động tình nguyện, sinh viên cần liên hệ phòng ban nào?</span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (971, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Tiền thân trường Đại học công nghệ Sài Gòn là trường nào?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (972, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Triết lý giáo dục của Trường Đại học Công nghệ Sài Gòn là gì?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (973, 'Nhiều lựa chọn Một câu trả lời', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Trường ĐH Công nghệ Sài Gòn đã có bao nhiêu khoa đạt được kiểm định chất lượng giáo dục theo chuẩn AUN-QA?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
INSERT INTO `savsoft_qbank` VALUES (974, 'Nhiều lựa chọn Một câu trả lời', '<p style=\"margin-left:36pt; margin-right:0cm\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> theo dõi kết quả điểm rèn luyện, sinh viên xem tại đâu?</span></span></span></span></p>\r\n', '', 59, 1, 0, 0, 0, 0);
