CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_attendance` AS select `savsoft_users`.`uid` AS `uid`,`savsoft_users`.`studentid` AS `studentid`,`savsoft_users`.`first_name` AS `first_name`,`savsoft_users`.`last_name` AS `last_name`,`savsoft_users`.`photo` AS `photo`,`savsoft_attendance`.`subject` AS `subject`,`savsoft_attendance`.`time1` AS `time1`,`savsoft_attendance`.`info_staff` AS `info_staff`,`savsoft_users`.`classid` AS `classid`,`savsoft_attendance`.`cid` AS `cid` from (`savsoft_users` join `savsoft_attendance` on(convert(`savsoft_attendance`.`studentid` using utf8mb3) = `savsoft_users`.`studentid`)) order by `savsoft_attendance`.`time1`;

