CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_form_student` AS select `xdpmweb_test`.`etp_form`.`name` AS `form_name`,`xdpmweb_test`.`etp_form`.`description` AS `form_description`,`xdpmweb_test`.`etp_form_student`.`formid` AS `formid`,`xdpmweb_test`.`etp_form_student`.`date1` AS `date1`,`xdpmweb_test`.`etp_form_student`.`date2` AS `date2`,`xdpmweb_test`.`etp_form_student`.`note` AS `note`,`xdpmweb_test`.`etp_form_student`.`data` AS `data`,`xdpmweb_test`.`etp_form_student`.`status` AS `status`,`xdpmweb_test`.`savsoft_users`.`uid` AS `uid`,`xdpmweb_test`.`savsoft_users`.`email` AS `email`,`xdpmweb_test`.`savsoft_users`.`first_name` AS `first_name`,`xdpmweb_test`.`savsoft_users`.`last_name` AS `last_name`,concat(`xdpmweb_test`.`savsoft_users`.`last_name`,' ',`xdpmweb_test`.`savsoft_users`.`first_name`) AS `full_name`,`xdpmweb_test`.`savsoft_users`.`gid` AS `gid`,`xdpmweb_test`.`savsoft_users`.`su` AS `su`,`xdpmweb_test`.`savsoft_users`.`photo` AS `photo`,`xdpmweb_test`.`savsoft_users`.`studentid` AS `studentid`,`xdpmweb_test`.`savsoft_users`.`classid` AS `classid`,`xdpmweb_test`.`savsoft_users`.`facultyid` AS `facultyid`,`xdpmweb_test`.`savsoft_users`.`birthdate` AS `birthdate`,`xdpmweb_test`.`savsoft_users`.`type` AS `type`,`xdpmweb_test`.`savsoft_users`.`academic_year` AS `academic_year`,`xdpmweb_test`.`etp_form_student`.`id` AS `id`,`xdpmweb_test`.`etp_form_student`.`get_at` AS `get_at`,`xdpmweb_test`.`etp_form_student`.`ReceivingAddress` AS `ReceivingAddress` from ((`savsoft_users` join `etp_form_student` on(`xdpmweb_test`.`savsoft_users`.`uid` = `xdpmweb_test`.`etp_form_student`.`uid`)) join `etp_form` on(`xdpmweb_test`.`etp_form_student`.`formid` = `xdpmweb_test`.`etp_form`.`formid`));

-- ----------------------------
-- View structure for v_form_student_0
-- ----------------------------
DROP VIEW IF EXISTS `v_form_student_0`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_form_student_0` AS select `v_form_student`.`id` AS `id`,`v_form_student`.`form_name` AS `form_name`,`v_form_student`.`full_name` AS `full_name`,`v_form_student`.`date1` AS `date1`,case when `v_form_student`.`status` = 0 then '0.Đơn mới' when `v_form_student`.`status` = 1 then '1.Đang xử lý' when `v_form_student`.`status` = 2 then '2.Đã hoàn thành' else '3.Đã in' end AS `status`,`v_form_student`.`date2` AS `date2`,`v_form_student`.`note` AS `note`,`v_form_student`.`formid` AS `formid`,`v_form_student`.`uid` AS `uid` from `v_form_student`;

