CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_info_user` AS select `savsoft_users`.`uid` AS `uid`,`savsoft_users`.`first_name` AS `first_name`,`savsoft_users`.`last_name` AS `last_name`,`savsoft_users`.`photo` AS `photo`,`savsoft_users`.`studentid` AS `studentid`,`savsoft_users`.`classid` AS `classid`,`savsoft_users`.`qrcode` AS `qrcode` from `savsoft_users`;

