-- ----------------------------
-- Procedure structure for filterAttendance
-- ----------------------------
DROP PROCEDURE IF EXISTS `filterAttendance`;
delimiter ;;
CREATE PROCEDURE `filterAttendance`(IN `date1` VARCHAR(10), IN `date2` VARCHAR(10), IN `cid_` VARCHAR(4), IN `faculty_id_` VARCHAR(10))
BEGIN  
	IF (cid_='') then 
			if ( faculty_id_='') then 
					select * from savsoft_attendance where time1 >= date1 and time1<= date2 ;
			else 	
	        select * from savsoft_attendance where time1 >= date1 and time1<= date2 and faculty_id=faculty_id_ ;
			end if;
	 else 
				if ( faculty_id_='') then 
					select * from savsoft_attendance where time1 >= date1 and time1<= date2 and cid=cid_;
			else 	
	        select * from savsoft_attendance where time1 >= date1 and time1<= date2 and faculty_id=faculty_id_  and cid=cid_;
			end if;
		end if;


END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for getDanhSachCaDiemDanh
-- ----------------------------
DROP PROCEDURE IF EXISTS `getDanhSachCaDiemDanh`;
delimiter ;;
CREATE PROCEDURE `getDanhSachCaDiemDanh`(IN `date1` VARCHAR(10), IN `date2` VARCHAR(10))
BEGIN
	
		select DISTINCT savsoft_attendance.date_class AS ngay_ca  from savsoft_attendance where time1>=date1 and time1<=date2 ;
	
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table savsoft_attendance
-- ----------------------------
DROP TRIGGER IF EXISTS `before_attendence_insert`;
delimiter ;;
CREATE TRIGGER `before_attendence_insert` BEFORE INSERT ON `savsoft_attendance` FOR EACH ROW BEGIN
  set	NEW.student_name = (select concat(last_name,' ', first_name) from savsoft_users where studentid=NEW.studentid);
	set NEW.class_id=(select classid from savsoft_users where studentid=NEW.studentid);
	set NEW.faculty_id= (select facultyid from savsoft_users where studentid=NEW.studentid);
	set NEW.course_name=(select etp_course.name from etp_course where etp_course.id = NEW.cid);
	set NEW.point=(select etp_course.point from etp_course where etp_course.id = NEW.cid ) ;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
